insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(3302, 'Cardiovascular Scenarios', 'AI Practice Question', 'A 58-year-old man in the ICU suddenly complains of crushing chest pain radiating to his left arm, with diaphoresis and nausea. The nurse''s FIRST priority action is to:', '["Give the patient a glass of water and reassess in 30 minutes", "Obtain a 12-lead ECG and vital signs while alerting the physician immediately", "Ask the patient to walk to the bathroom to see if pain resolves", "Document the complaint and continue the routine round"]'::jsonb, 1, 'Suspected acute coronary syndrome requires an immediate 12-lead ECG and vital signs alongside urgent physician notification — time is myocardium.', 'Cardiovascular', '🫀', true),
(3303, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with a pulmonary artery catheter (PAC) in place develops a persistently wedged waveform. The nurse''s most appropriate immediate action is to:', '["Inflate the balloon further to confirm the wedge", "Deflate the balloon immediately and reposition/notify the physician, as a permanently wedged catheter risks pulmonary infarction", "Ignore it since PAC waveforms fluctuate normally", "Increase the IV fluid rate"]'::jsonb, 1, 'A persistently wedged PAC risks pulmonary artery rupture or infarction — the balloon must be deflated immediately and the catheter position addressed.', 'Cardiovascular', '🫀', true),
(3304, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient develops new-onset atrial fibrillation with a rapid ventricular rate and becomes hypotensive with altered mental status. The most appropriate immediate management is:', '["Oral rate-control medication only", "Urgent synchronized cardioversion, given haemodynamic instability", "Watchful waiting for 24 hours", "Administering a fluid bolus alone"]'::jsonb, 1, 'Unstable atrial fibrillation with hypotension and altered mental status is an indication for urgent synchronized cardioversion, not oral medication or observation.', 'Cardiovascular', '🫀', true),
(3305, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient post-myocardial infarction develops new-onset crackles bilaterally, a third heart sound (S3), and worsening dyspnoea. This most likely indicates:', '["Simple anxiety", "Acute left ventricular failure/pulmonary oedema", "Normal post-MI recovery", "Gastro-oesophageal reflux"]'::jsonb, 1, 'Bilateral crackles, an S3 gallop, and dyspnoea after MI are classic signs of acute left ventricular failure with pulmonary oedema.', 'Cardiovascular', '🫀', true),
(3306, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient receiving an intra-aortic balloon pump (IABP) suddenly develops a cold, pulseless left leg. The nurse should suspect:', '["Normal side effect requiring no action", "Limb ischaemia from the IABP catheter, requiring urgent assessment and intervention", "A simple positioning issue with no urgency", "An allergic reaction to the dressing"]'::jsonb, 1, 'IABP insertion carries a risk of distal limb ischaemia — a cold, pulseless limb after insertion is a vascular emergency requiring urgent assessment.', 'Cardiovascular', '🫀', true),
(3307, 'Cardiovascular Scenarios', 'AI Practice Question', 'On haemodynamic monitoring, a patient shows low cardiac output, high systemic vascular resistance, and a high pulmonary capillary wedge pressure. This pattern is most consistent with:', '["Distributive (septic) shock", "Cardiogenic shock", "Hypovolaemic shock", "Normal haemodynamics"]'::jsonb, 1, 'Cardiogenic shock classically shows low cardiac output with compensatory high SVR and elevated filling pressures (high wedge pressure) due to pump failure.', 'Cardiovascular', '🫀', true),
(3308, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient on continuous ECG monitoring develops wide, bizarre QRS complexes at a rate of 160/min with no discernible P waves, and is hypotensive. This rhythm most likely represents:', '["Sinus tachycardia", "Ventricular tachycardia", "Normal sinus rhythm", "First-degree heart block"]'::jsonb, 1, 'Wide, bizarre QRS complexes without P waves at a rapid rate is characteristic of ventricular tachycardia, a life-threatening arrhythmia especially when the patient is unstable.', 'Cardiovascular', '🫀', true),
(3309, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with cardiac tamponade would be expected to show which combination of findings (Beck''s Triad)?', '["Hypertension, bradycardia, loud heart sounds", "Hypotension, jugular venous distension, muffled heart sounds", "Fever, cough, wheeze", "Polyuria, polydipsia, weight loss"]'::jsonb, 1, 'Beck''s Triad — hypotension, elevated JVP, and muffled/distant heart sounds — is classic for cardiac tamponade.', 'Cardiovascular', '🫀', true),
(3310, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient receiving IV nitroglycerin for angina develops a headache and drop in blood pressure. The nurse should:', '["Stop the infusion abruptly without informing anyone", "Recognise these as expected effects, monitor BP closely, and adjust the infusion rate per protocol/orders", "Increase the rate to relieve the headache faster", "Give an antihypertensive bolus immediately"]'::jsonb, 1, 'Headache and hypotension are known nitroglycerin side effects from vasodilation — the infusion is titrated based on BP response rather than abruptly stopped without assessment.', 'Cardiovascular', '🫀', true),
(3311, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient''s ECG shows ST-segment depression in the anterior leads during an episode of chest pain, which resolves when the pain resolves. This pattern most likely represents:', '["Old, resolved myocardial infarction with no current significance", "Myocardial ischaemia", "Normal variant with no clinical significance", "Ventricular hypertrophy only"]'::jsonb, 1, 'Transient ST depression correlating with chest pain onset and resolution is a hallmark of myocardial ischaemia.', 'Cardiovascular', '🫀', true),
(3312, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with congestive heart failure is prescribed a diuretic. The nurse should prioritise monitoring for:', '["Hyperglycaemia only", "Electrolyte imbalances (especially potassium), fluid status, and renal function", "Increased appetite", "Improved hearing"]'::jsonb, 1, 'Diuretics can cause significant electrolyte disturbances (especially hypokalaemia with loop/thiazide diuretics), volume depletion, and changes in renal function requiring close monitoring.', 'Cardiovascular', '🫀', true),
(3313, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient in cardiogenic shock is started on dobutamine. The nurse understands this drug is chosen primarily because it:', '["Is a pure vasoconstrictor with no cardiac effect", "Increases myocardial contractility and cardiac output", "Lowers heart rate significantly", "Has no effect on blood pressure"]'::jsonb, 1, 'Dobutamine is an inotrope that increases myocardial contractility and cardiac output, making it useful in cardiogenic shock/low cardiac output states.', 'Cardiovascular', '🫀', true),
(3314, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient develops sudden severe chest pain described as ''tearing,'' radiating to the back, with unequal blood pressures in both arms. This presentation should raise urgent suspicion of:', '["Simple musculoskeletal pain", "Aortic dissection", "Gastro-oesophageal reflux", "Panic attack"]'::jsonb, 1, 'Tearing chest pain radiating to the back with unequal limb blood pressures is a classic presentation of aortic dissection, a surgical emergency.', 'Cardiovascular', '🫀', true),
(3315, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with a permanent pacemaker shows a rhythm strip with pacer spikes not followed by a QRS complex. This indicates:', '["Normal pacemaker function", "Failure to capture — the pacemaker impulse is not depolarising the myocardium", "Battery is fully charged with no issue", "Over-sensing with no clinical relevance"]'::jsonb, 1, 'A pacer spike not followed by a QRS complex indicates failure to capture, meaning the pacing stimulus is not successfully triggering ventricular depolarisation — a malfunction requiring evaluation.', 'Cardiovascular', '🫀', true),
(3316, 'Cardiovascular', 'AI Practice Question', 'Preload refers to:', '["The resistance the heart must pump against", "The degree of stretch of cardiac muscle fibres at the end of diastole, related to venous return", "The heart''s intrinsic contractility only", "The heart rate"]'::jsonb, 1, 'Preload is the ventricular wall stretch/tension at end-diastole, determined largely by venous return and filling volume.', 'Cardiovascular', '🫀', true),
(3317, 'Cardiovascular', 'AI Practice Question', 'Afterload refers to:', '["The volume of blood returning to the heart", "The resistance the ventricle must overcome to eject blood", "The heart''s electrical conduction speed", "The volume of the atria"]'::jsonb, 1, 'Afterload is the resistance (largely systemic vascular resistance) the ventricle must overcome to eject blood during systole.', 'Cardiovascular', '🫀', true),
(3318, 'Cardiovascular', 'AI Practice Question', 'Contractility refers to the heart''s:', '["Rate of electrical impulse generation only", "Intrinsic ability of cardiac muscle fibres to contract, independent of preload/afterload changes", "Valve competency", "Coronary blood flow"]'::jsonb, 1, 'Contractility is the intrinsic strength of cardiac muscle contraction, a property distinct from preload and afterload though all three affect cardiac output.', 'Cardiovascular', '🫀', true),
(3319, 'Cardiovascular', 'AI Practice Question', 'A murmur is best described as:', '["A normal, expected heart sound in all patients", "An abnormal, often turbulent blood-flow sound, typically related to valve or structural heart disease", "A type of arrhythmia", "A measure of blood pressure"]'::jsonb, 1, 'A murmur is an abnormal heart sound caused by turbulent blood flow, often related to valvular or structural cardiac abnormalities.', 'Cardiovascular', '🫀', true),
(3320, 'Cardiovascular', 'AI Practice Question', 'A heart block occurs when there is:', '["Complete absence of any cardiac electrical activity", "A delay or interruption in the electrical conduction system of the heart", "Excessive contractility of the ventricles", "A structural valve defect only"]'::jsonb, 1, 'Heart block refers to a delay or interruption in the heart''s normal electrical conduction pathway, which can range from mild (first-degree) to complete.', 'Cardiovascular', '🫀', true),
(3321, 'Cardiovascular', 'AI Practice Question', 'A patient in hypovolaemic shock from acute blood loss would be expected to show which haemodynamic pattern?', '["High cardiac output, low SVR", "Low cardiac output, high SVR, low filling pressures", "Normal cardiac output with no haemodynamic change", "High filling pressures with low SVR"]'::jsonb, 1, 'Hypovolaemic shock causes low cardiac output from reduced circulating volume, compensatory vasoconstriction (high SVR), and low cardiac filling pressures.', 'Cardiovascular', '🫀', true),
(3322, 'Cardiovascular Scenarios', 'AI Practice Question', 'A nurse is comparing the effects of two vasopressors on a patient''s haemodynamic profile. Noradrenaline predominantly causes vasoconstriction (raising SVR/BP with modest heart rate effect), while dobutamine predominantly:', '["Causes profound vasoconstriction with no inotropic effect", "Increases myocardial contractility and cardiac output, with relatively less vasoconstrictive effect", "Has an identical haemodynamic profile to noradrenaline", "Lowers cardiac output significantly"]'::jsonb, 1, 'Noradrenaline is primarily a vasoconstrictor (alpha-agonist) raising blood pressure, while dobutamine is primarily an inotrope (beta-agonist) increasing contractility/cardiac output with less vasoconstriction.', 'Cardiovascular', '🫀', true),
(3323, 'Cardiovascular Scenarios', 'AI Practice Question', 'A trauma patient in hypovolaemic shock has lost an estimated 35% of their circulating blood volume. According to classification of haemorrhagic shock, this places them in:', '["Class I", "Class II", "Class III", "Class IV"]'::jsonb, 2, 'Class III haemorrhage is generally defined as 30–40% blood volume loss, associated with significant hypotension and tachycardia requiring urgent blood product resuscitation.', 'Cardiovascular', '🫀', true),
(3324, 'Cardiovascular', 'AI Practice Question', 'End Tidal CO2 (EtCO2) monitoring during CPR is useful mainly because a sustained EtCO2 above a certain threshold suggests:', '["Ineffective chest compressions with no perfusion", "Effective chest compressions/return of spontaneous circulation is more likely", "No relationship to CPR quality", "Only relevant for ventilated non-arrest patients"]'::jsonb, 1, 'A sustained rise in EtCO2 during CPR reflects improved pulmonary blood flow from effective compressions and can signal return of spontaneous circulation.', 'Respiratory', '🫁', true),
(3325, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with suspected myocardial infarction has ECG changes showing ST elevation in leads II, III, and aVF. This localises the infarction to the:', '["Anterior wall", "Inferior wall", "Lateral wall", "Posterior wall only"]'::jsonb, 1, 'Leads II, III and aVF reflect the inferior wall of the left ventricle, supplied typically by the right coronary artery.', 'Cardiovascular', '🫀', true),
(3326, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient receiving thrombolytic therapy for acute MI should be closely monitored for the major complication of:', '["Constipation", "Bleeding, including intracranial haemorrhage", "Weight gain", "Hypoglycaemia"]'::jsonb, 1, 'The major serious complication of thrombolytic therapy is bleeding, with intracranial haemorrhage being the most feared, requiring careful patient selection and monitoring.', 'Cardiovascular', '🫀', true),
(3327, 'Cardiovascular', 'AI Practice Question', 'The Swan-Ganz (pulmonary artery) catheter allows measurement of:', '["Only peripheral blood pressure", "Right heart pressures, pulmonary artery pressure, and pulmonary capillary wedge pressure (an estimate of left atrial pressure)", "Only body temperature", "Only oxygen saturation"]'::jsonb, 1, 'The Swan-Ganz catheter measures right heart and pulmonary artery pressures, and provides wedge pressure as an estimate of left atrial/left ventricular filling pressure.', 'Cardiovascular', '🫀', true),
(3328, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient''s ECG shows a regular rhythm with a heart rate of 42 bpm and normal, narrow QRS complexes. The patient is symptomatic with dizziness. The priority intervention is likely to be:', '["No intervention needed since QRS is narrow", "Atropine and preparation for possible transcutaneous pacing per protocol", "Immediate defibrillation", "Administering a beta-blocker"]'::jsonb, 1, 'Symptomatic bradycardia is managed with atropine as first-line pharmacological treatment, with transcutaneous pacing available if atropine is ineffective — defibrillation and beta-blockers are inappropriate here.', 'Cardiovascular', '🫀', true),
(3329, 'Cardiovascular', 'AI Practice Question', 'Extra heart sounds such as S3 and S4 gallops are best assessed using which part of the stethoscope, and in which patient position?', '["The diaphragm, with the patient standing", "The bell, with the patient in the left lateral position", "Only visually, without a stethoscope", "The diaphragm, with the patient prone"]'::jsonb, 1, 'Low-pitched extra heart sounds like S3/S4 gallops are best heard using the bell of the stethoscope with the patient positioned in the left lateral decubitus position.', 'Cardiovascular', '🫀', true),
(3330, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient post-cardiac surgery develops decreasing chest tube output that suddenly stops, along with hypotension, rising CVP, and muffled heart sounds. This should raise urgent suspicion of:', '["Normal recovery", "Cardiac tamponade from clotted chest tubes/accumulating pericardial blood", "Simple hypovolaemia from over-diuresis", "Wound infection"]'::jsonb, 1, 'Sudden cessation of chest tube drainage with hypotension, rising CVP and muffled heart sounds post-cardiac surgery suggests tamponade from a clotted drain allowing blood/fluid to accumulate around the heart.', 'Cardiovascular', '🫀', true),
(3331, 'Respiratory Scenarios', 'AI Practice Question', 'A mechanically ventilated patient''s high-pressure alarm sounds repeatedly. On assessment, breath sounds are decreased on the right with tracheal deviation to the left and hyper-resonance on percussion. The nurse should suspect:', '["Mucus plug in the right main bronchus", "Tension pneumothorax on the right", "Pulmonary oedema", "Normal ventilator function"]'::jsonb, 1, 'Decreased breath sounds, tracheal deviation away from the affected side, and hyper-resonance are classic signs of tension pneumothorax — a life-threatening emergency requiring immediate needle decompression.', 'Respiratory', '🫁', true),
(3332, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with acute severe asthma has a silent chest on auscultation. The nurse should interpret this as:', '["A reassuring sign that the asthma is resolving", "An ominous sign of minimal air movement/impending respiratory failure", "Normal findings for an asthmatic patient", "A sign of over-treatment with bronchodilators"]'::jsonb, 1, 'A silent chest means almost no air is moving due to severe airway obstruction — this is an extremely dangerous sign requiring urgent escalation, not reassurance.', 'Respiratory', '🫁', true),
(3333, 'Respiratory Scenarios', 'AI Practice Question', 'A patient on mechanical ventilation for ARDS is being managed with low tidal volumes (around 6ml/kg predicted body weight). The rationale for this strategy is primarily to:', '["Maximise oxygen delivery regardless of pressure", "Minimise ventilator-induced lung injury (volutrauma/barotrauma) in already-injured lungs", "Reduce the work of the ventilator motor", "Increase patient comfort only"]'::jsonb, 1, 'Lung-protective ventilation with low tidal volumes reduces overdistension and ventilator-induced lung injury in the already-damaged lungs of ARDS patients.', 'Respiratory', '🫁', true),
(3334, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with COPD receiving oxygen therapy develops worsening drowsiness and a rising respiratory rate that then slows dramatically. The nurse should suspect:', '["Improved oxygenation with no concern", "CO2 narcosis from excessive oxygen therapy suppressing hypoxic respiratory drive", "A simple anxiety reaction", "Normal sleep pattern"]'::jsonb, 1, 'In some chronic CO2-retaining COPD patients, excessive oxygen can blunt hypoxic respiratory drive, leading to hypoventilation, rising CO2, and eventual CO2 narcosis with drowsiness.', 'Respiratory', '🫁', true),
(3335, 'Respiratory Scenarios', 'AI Practice Question', 'A patient''s arterial blood gas shows pH 7.28, PaCO2 60mmHg, HCO3 26mmol/L. This is most consistent with:', '["Uncompensated metabolic alkalosis", "Uncompensated (acute) respiratory acidosis", "Fully compensated respiratory alkalosis", "Normal ABG"]'::jsonb, 1, 'A low pH with an elevated PaCO2 and near-normal HCO3 indicates an acute (largely uncompensated) respiratory acidosis, typically from hypoventilation.', 'Respiratory', '🫁', true),
(3336, 'Respiratory Scenarios', 'AI Practice Question', 'A patient develops sudden dyspnoea, pleuritic chest pain, and tachycardia after prolonged bed rest post-surgery. The nurse should have a high index of suspicion for:', '["Simple anxiety", "Pulmonary embolism", "Common cold", "Gastritis"]'::jsonb, 1, 'Sudden dyspnoea, pleuritic chest pain and tachycardia after a period of immobility (a VTE risk factor) should raise strong suspicion for pulmonary embolism.', 'Respiratory', '🫁', true),
(3337, 'Respiratory Scenarios', 'AI Practice Question', 'During suctioning of an intubated patient, the nurse should limit each suction pass to approximately:', '["60 seconds", "10–15 seconds", "5 minutes", "No time limit is necessary"]'::jsonb, 1, 'Suctioning should be limited to about 10–15 seconds per pass to minimise hypoxia, as suction removes oxygen along with secretions.', 'Respiratory', '🫁', true),
(3338, 'Respiratory Scenarios', 'AI Practice Question', 'A patient on PEEP (Positive End-Expiratory Pressure) develops sudden hypotension after the PEEP level is increased. The most likely explanation is:', '["PEEP has no cardiovascular effects", "Increased intrathoracic pressure reducing venous return and cardiac output", "An allergic reaction to the ventilator tubing", "Coincidental, unrelated hypotension"]'::jsonb, 1, 'High PEEP increases intrathoracic pressure, which can reduce venous return to the heart and subsequently lower cardiac output and blood pressure.', 'Respiratory', '🫁', true),
(3339, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with a chest tube for pneumothorax shows continuous bubbling in the water seal chamber. This most likely indicates:', '["Normal, expected drainage with no concern", "An air leak, either from the patient''s pleural space or the drainage system", "The drain is blocked", "The patient''s lung has fully re-expanded"]'::jsonb, 1, 'Continuous bubbling in the water seal chamber indicates an ongoing air leak, which could be from the pleural space (persistent pneumothorax) or a system connection issue requiring assessment.', 'Respiratory', '🫁', true),
(3340, 'Respiratory Scenarios', 'AI Practice Question', 'A patient''s chest tube water seal chamber shows fluid that stops fluctuating (''swinging'') with respiration. This most likely indicates:', '["The lung has fully re-expanded, or the tube is blocked/kinked", "Normal ongoing function", "An air leak", "Excessive suction"]'::jsonb, 0, 'Cessation of swinging can indicate either successful lung re-expansion (a good sign) or a blocked/kinked tube (concerning) — the nurse must assess further to distinguish between the two.', 'Respiratory', '🫁', true),
(3341, 'Respiratory', 'AI Practice Question', 'The modified Allen''s test is performed before arterial blood gas sampling primarily to:', '["Assess collateral circulation to the hand via the ulnar artery before radial artery puncture", "Measure blood pressure", "Assess for infection at the puncture site", "Determine the patient''s pain tolerance"]'::jsonb, 0, 'The modified Allen''s test checks for adequate collateral (ulnar) circulation to the hand before puncturing the radial artery, reducing the risk of ischaemic complications.', 'Respiratory', '🫁', true),
(3342, 'Respiratory', 'AI Practice Question', 'A normal PaO2 on arterial blood gas analysis is generally considered to be:', '["Above 80mmHg", "Below 40mmHg", "Exactly 20mmHg", "Above 200mmHg always required"]'::jsonb, 0, 'A normal PaO2 is generally above 80mmHg on room air, reflecting adequate oxygenation.', 'Respiratory', '🫁', true),
(3343, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with ARDS has a PaO2/FiO2 ratio of 150. According to the Berlin definition, this falls into which severity category?', '["Mild ARDS", "Moderate ARDS", "Severe ARDS", "Not ARDS"]'::jsonb, 1, 'Under the Berlin definition, a PaO2/FiO2 ratio of 100–200 (with PEEP ≥5) is classified as moderate ARDS.', 'Respiratory', '🫁', true),
(3344, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with a tracheostomy develops sudden respiratory distress and the nurse cannot pass a suction catheter through the tube. The priority action is to:', '["Wait 10 minutes and try again", "Suspect tube obstruction and follow emergency tracheostomy protocol (e.g. attempt to clear/change the tube), calling for help", "Increase oxygen flow and do nothing else", "Remove the tracheostomy tube and discard it with no replacement plan"]'::jsonb, 1, 'Inability to pass a suction catheter with respiratory distress suggests tube obstruction — an airway emergency requiring immediate action per tracheostomy emergency protocol and calling for help.', 'Respiratory', '🫁', true),
(3345, 'Respiratory', 'AI Practice Question', 'Humidification of inspired gases in a mechanically ventilated patient is important primarily to:', '["Increase oxygen concentration", "Prevent drying and thickening of secretions, which could otherwise obstruct the airway", "Cool the patient''s body temperature", "Reduce ventilator noise"]'::jsonb, 1, 'The upper airway''s normal humidifying function is bypassed by intubation, so artificial humidification prevents secretions from drying/thickening and obstructing the airway.', 'Respiratory', '🫁', true),
(3346, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with status asthmaticus who has been on continuous nebulised salbutamol develops a heart rate of 150 and serum potassium of 2.9mmol/L. The nurse recognises this as:', '["An unrelated coincidental finding requiring no action", "A known salbutamol side effect (tachycardia, hypokalaemia) requiring monitoring and potassium replacement", "A sign the treatment is not working at all", "An indication to increase the salbutamol dose further"]'::jsonb, 1, 'Beta-2 agonists like salbutamol commonly cause tachycardia and hypokalaemia (by driving potassium into cells) — this requires monitoring and correction, not simply increasing the dose.', 'Respiratory', '🫁', true),
(3347, 'Respiratory', 'AI Practice Question', 'Which mode of mechanical ventilation delivers a preset volume/pressure with every breath, whether patient-triggered or machine-triggered, providing full support?', '["CPAP with no additional support", "Assist-Control (AC)", "Pressure Support Ventilation alone at low levels", "T-piece trial"]'::jsonb, 1, 'Assist-Control ventilation delivers a full preset breath for every triggered or mandatory breath, providing complete ventilatory support.', 'Respiratory', '🫁', true),
(3348, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with acute respiratory distress has an SpO2 of 88% on room air. The most appropriate immediate nursing action is to:', '["Document and reassess in 4 hours", "Apply supplemental oxygen and reassess respiratory status promptly", "Ignore it if the patient appears comfortable", "Discontinue all monitoring"]'::jsonb, 1, 'An SpO2 of 88% indicates significant hypoxaemia requiring prompt supplemental oxygen and reassessment, not delay.', 'Respiratory', '🫁', true),
(3349, 'Respiratory', 'AI Practice Question', 'The purpose of an oropharyngeal airway (Guedel airway) in an unconscious patient is to:', '["Provide long-term ventilation support", "Prevent the tongue from obstructing the airway in an unconscious patient with intact gag reflex absent", "Deliver medication directly to the lungs", "Measure oxygen saturation"]'::jsonb, 1, 'An oropharyngeal airway holds the tongue forward to prevent airway obstruction in an unconscious patient without a gag reflex; it is not tolerated in a conscious patient.', 'Respiratory', '🫁', true),
(3350, 'Respiratory Scenarios', 'AI Practice Question', 'A patient is intubated for airway protection after a severe head injury. During intubation, the nurse should anticipate the need to:', '["Allow free neck movement to ease the procedure", "Maintain cervical spine precautions/in-line stabilisation given possible associated spinal injury", "Hyperextend the neck fully for best view", "Avoid any pre-oxygenation"]'::jsonb, 1, 'Trauma patients require cervical spine precautions during intubation until injury is excluded, since neck manipulation could worsen an occult spinal injury.', 'Respiratory', '🫁', true),
(3351, 'Respiratory', 'AI Practice Question', 'Biphasic Positive Airway Pressure (BiPAP) differs from CPAP mainly in that BiPAP provides:', '["A single constant pressure only", "Two different pressure levels — higher on inspiration, lower on expiration — providing additional inspiratory support", "No pressure support at all", "Only oxygen with no pressure component"]'::jsonb, 1, 'BiPAP delivers two pressure levels (IPAP and EPAP), providing inspiratory pressure support in addition to the expiratory pressure that CPAP alone provides.', 'Respiratory', '🫁', true),
(3352, 'Respiratory Scenarios', 'AI Practice Question', 'A patient recovering from thoracotomy has thick, tenacious secretions and a weak cough. The most appropriate nursing intervention is to:', '["Withhold analgesia to encourage a stronger cough", "Provide adequate analgesia, encourage deep breathing/coughing (splinting the incision), and consider chest physiotherapy", "Discourage any mobilisation", "Avoid humidified oxygen"]'::jsonb, 1, 'Effective secretion clearance after thoracotomy relies on adequate pain control (to allow effective coughing), incision splinting, chest physiotherapy, and mobilisation.', 'Respiratory', '🫁', true),
(3353, 'Respiratory', 'AI Practice Question', 'A pleural effusion is best described as:', '["Air in the pleural space", "Abnormal accumulation of fluid in the pleural space", "A collapsed lung from mucus plugging", "A congenital lung malformation"]'::jsonb, 1, 'A pleural effusion is an abnormal accumulation of fluid between the visceral and parietal pleura.', 'Respiratory', '🫁', true),
(3354, 'Respiratory Scenarios', 'AI Practice Question', 'A patient develops sudden dyspnoea after a large-volume thoracentesis for pleural effusion. The nurse should suspect which complication?', '["Normal, expected relief of symptoms", "Re-expansion pulmonary oedema or iatrogenic pneumothorax", "Improved lung function with no concern", "Simple anxiety about the procedure"]'::jsonb, 1, 'Rapid large-volume fluid removal during thoracentesis carries a risk of re-expansion pulmonary oedema, and the procedure itself risks iatrogenic pneumothorax — both should be considered with new dyspnoea.', 'Respiratory', '🫁', true),
(3355, 'Respiratory', 'AI Practice Question', 'Ventilator-Associated Pneumonia (VAP) prevention bundles typically include which of the following elements?', '["Keeping the head of bed flat at all times", "Elevating the head of bed 30–45 degrees, daily sedation interruption, and oral care", "Avoiding hand hygiene to reduce irritation", "Continuous heavy sedation with no interruption"]'::jsonb, 1, 'VAP prevention bundles typically include head-of-bed elevation, daily sedation vacations/spontaneous breathing trials, and regular oral care, among other measures.', 'Respiratory', '🫁', true),
(3356, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with acute respiratory failure has a respiratory rate of 6/min and is difficult to rouse after opioid administration. The nurse''s priority action is to:', '["Administer another dose of opioid to calm the patient", "Support ventilation as needed, administer naloxone as prescribed, and closely monitor", "Increase the opioid infusion rate", "Do nothing since the patient appears calm"]'::jsonb, 1, 'A respiratory rate of 6/min with reduced consciousness after opioids indicates opioid-induced respiratory depression — ventilatory support and naloxone administration are priorities.', 'Respiratory', '🫁', true),
(3357, 'Respiratory', 'AI Practice Question', 'A patient''s arterial blood gas shows pH 7.50, PaCO2 28mmHg, HCO3 24mmol/L. This is most consistent with:', '["Uncompensated respiratory alkalosis", "Metabolic acidosis", "Respiratory acidosis", "Normal ABG"]'::jsonb, 0, 'An elevated pH with low PaCO2 and near-normal HCO3 indicates an acute (largely uncompensated) respiratory alkalosis, typically from hyperventilation.', 'Respiratory', '🫁', true),
(3358, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with severe ARDS remains hypoxic despite optimal ventilator settings. The team considers proning the patient. The primary rationale for prone positioning is to:', '["Improve patient comfort only", "Improve ventilation-perfusion matching and recruit dependent lung regions, improving oxygenation", "Reduce the need for sedation", "Prevent pressure ulcers exclusively"]'::jsonb, 1, 'Prone positioning in severe ARDS improves oxygenation by recruiting previously dependent, poorly ventilated lung regions and improving V/Q matching.', 'Respiratory', '🫁', true),
(3359, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a head injury has a Glasgow Coma Scale score that drops from 14 to 9 over two hours, with a newly dilated, non-reactive left pupil. The nurse should suspect:', '["Normal fluctuation requiring no action", "Rising intracranial pressure with possible uncal herniation, requiring urgent physician notification", "Simple fatigue", "A pre-existing condition unrelated to the injury"]'::jsonb, 1, 'A falling GCS with a unilateral dilated, non-reactive pupil is a classic sign of rising ICP with uncal herniation compressing the oculomotor nerve — a neurosurgical emergency.', 'Neurology', '🧠', true),
(3360, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a traumatic brain injury shows the Cushing''s Triad of hypertension, bradycardia, and irregular respirations. This indicates:', '["Improving neurological status", "Severely elevated intracranial pressure — a late, ominous sign", "Normal vital sign variation", "Dehydration"]'::jsonb, 1, 'Cushing''s Triad (hypertension, bradycardia, irregular respiration) is a late and ominous sign of critically raised intracranial pressure, reflecting brainstem compression.', 'Neurology', '🧠', true),
(3361, 'Neurology Scenarios', 'AI Practice Question', 'A patient with increased intracranial pressure is being nursed. Which positioning is generally recommended to help reduce ICP?', '["Head of bed flat, neck flexed", "Head of bed elevated 30 degrees, head in neutral alignment", "Trendelenburg (head down) position", "Prone position"]'::jsonb, 1, 'Elevating the head of bed to about 30 degrees with the head in neutral alignment promotes venous drainage and helps reduce intracranial pressure.', 'Neurology', '🧠', true),
(3362, 'Neurology Scenarios', 'AI Practice Question', 'A patient presents with sudden onset of facial droop, slurred speech, and unilateral arm weakness. The nurse''s priority action is to:', '["Wait several hours to see if symptoms resolve on their own", "Recognise these as stroke warning signs, note time of onset, and activate the emergency stroke protocol immediately", "Give the patient oral fluids first", "Document and continue routine care"]'::jsonb, 1, 'Facial droop, slurred speech and unilateral weakness are classic stroke signs (FAST) — time-critical action and noting exact onset time are essential since treatment windows are narrow.', 'Neurology', '🧠', true),
(3363, 'Neurology Scenarios', 'AI Practice Question', 'Differentiating ischaemic from haemorrhagic stroke is critical primarily because:', '["Both are treated identically regardless of type", "Thrombolytic therapy is beneficial in ischaemic stroke but contraindicated (and harmful) in haemorrhagic stroke", "Haemorrhagic stroke never requires urgent treatment", "Only ischaemic stroke requires imaging"]'::jsonb, 1, 'Thrombolytics can be life-saving in ischaemic stroke but would be catastrophic in haemorrhagic stroke by worsening bleeding — CT imaging must confirm the type before treatment.', 'Neurology', '🧠', true),
(3364, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a Glasgow Coma Scale eye-opening score of 2 demonstrates:', '["Spontaneous eye opening", "Eye opening to voice", "Eye opening to pain only", "No eye opening at all"]'::jsonb, 2, 'On the GCS eye-opening component, a score of 2 corresponds to eye opening only in response to painful stimulus.', 'Neurology', '🧠', true),
(3365, 'Neurology Scenarios', 'AI Practice Question', 'A patient in status epilepticus (seizure lasting over 5 minutes) is given IV lorazepam with no effect after two doses. The next step in management is typically:', '["Wait and observe with no further intervention", "Second-line therapy such as IV phenytoin/fosphenytoin loading", "Discharge home for outpatient follow-up", "Oral anticonvulsant only"]'::jsonb, 1, 'When benzodiazepines fail to terminate status epilepticus, second-line agents such as IV phenytoin (or levetiracetam) are used per standard protocols.', 'Neurology', '🧠', true),
(3366, 'Neurology Scenarios', 'AI Practice Question', 'A pregnant patient with severe pre-eclampsia develops a tonic-clonic seizure. The immediate management priority is:', '["IV lorazepam as first-line", "IV magnesium sulfate, which is first-line for eclamptic seizures", "No treatment is needed since seizures in pregnancy resolve spontaneously", "Immediate general anaesthesia for delivery with no other intervention"]'::jsonb, 1, 'Magnesium sulfate is first-line for eclamptic seizures specifically — not benzodiazepines, which are reserved for non-eclamptic seizures or refractory cases.', 'Neurology', '🧠', true),
(3367, 'Neurology Scenarios', 'AI Practice Question', 'While monitoring a patient on magnesium sulfate for eclampsia, the nurse notes absent deep tendon reflexes and a respiratory rate of 10/min. This suggests:', '["The dose is subtherapeutic and should be increased", "Magnesium toxicity, requiring the infusion to be stopped and calcium gluconate prepared as an antidote", "Normal expected findings requiring no action", "An unrelated finding"]'::jsonb, 1, 'Absent reflexes and respiratory depression are signs of magnesium toxicity — the infusion should be stopped and calcium gluconate (the antidote) prepared per protocol.', 'Neurology', '🧠', true),
(3368, 'Neurology Scenarios', 'AI Practice Question', 'A patient with Guillain-Barré Syndrome is being monitored closely in the ICU primarily because of the risk of:', '["Skin rash only", "Ascending paralysis leading to respiratory muscle failure", "Mild joint pain only", "Improved mobility over time with no monitoring needed"]'::jsonb, 1, 'Guillain-Barré Syndrome causes ascending paralysis that can progress to involve the respiratory muscles, requiring close monitoring of respiratory function (e.g. vital capacity) for potential ventilatory failure.', 'Neurology', '🧠', true),
(3369, 'Neurology Scenarios', 'AI Practice Question', 'A patient with myasthenia gravis in a myasthenic crisis presents with worsening muscle weakness and respiratory difficulty. The priority nursing concern is:', '["Skin integrity only", "Close monitoring of respiratory status/vital capacity, with readiness for ventilatory support", "Nutritional intake only", "Pain management only"]'::jsonb, 1, 'Myasthenic crisis can rapidly progress to respiratory failure from severe muscle weakness, making respiratory monitoring and readiness for ventilatory support the priority.', 'Neurology', '🧠', true),
(3370, 'Neurology Scenarios', 'AI Practice Question', 'A patient with tetanus develops severe muscle spasms triggered by minor stimuli such as light and noise. The most appropriate environmental nursing intervention is to:', '["Increase environmental stimulation to distract the patient", "Provide a quiet, dark, low-stimulation room to minimise spasm triggers", "Keep the television and lights on continuously", "Encourage frequent visitors for company"]'::jsonb, 1, 'Tetanus spasms are triggered by external stimuli, so a quiet, dark, minimally stimulating environment is a core supportive nursing intervention.', 'Neurology', '🧠', true),
(3371, 'Neurology Scenarios', 'AI Practice Question', 'A patient in the ICU develops new-onset agitation, disorientation, and pulling at lines, fluctuating throughout the day. The nurse should assess for:', '["Normal ICU behaviour requiring no assessment", "ICU delirium, using a validated delirium assessment tool", "Definite dementia with no other cause considered", "Nothing — this is expected and not clinically significant"]'::jsonb, 1, 'Fluctuating attention/cognition disturbance in the ICU should prompt formal delirium screening (e.g. CAM-ICU), since delirium is common, often reversible, but frequently under-recognised (especially the hypoactive form).', 'Neurology', '🧠', true),
(3372, 'Neurology Scenarios', 'AI Practice Question', 'A hypoactive delirium presentation in an ICU patient is most likely to be characterised by:', '["Agitation and combativeness, making it easy to identify", "Quiet withdrawal and reduced responsiveness, making it easily missed if not specifically assessed", "Loud, disruptive behaviour", "Improved alertness compared to baseline"]'::jsonb, 1, 'Hypoactive delirium presents with quiet withdrawal rather than agitation, making it the most commonly missed subtype unless specifically screened for.', 'Neurology', '🧠', true),
(3373, 'Neurology Scenarios', 'AI Practice Question', 'Physical restraints are generally discouraged in managing ICU delirium because they:', '["Always calm the agitated patient effectively", "Can worsen agitation and delirium, and carry their own complications", "Have no known drawbacks", "Are required by law in every ICU"]'::jsonb, 1, 'Physical restraints can paradoxically worsen agitation/delirium and carry risks of injury — non-pharmacological strategies (reorientation, sleep hygiene, minimising tethers) are preferred first.', 'Neurology', '🧠', true),
(3374, 'Neurology', 'AI Practice Question', 'The Glasgow Coma Scale assesses three components:', '["Eye opening, verbal response, and motor response", "Pulse, blood pressure, and respiratory rate", "Pupil size, skin colour, and temperature", "Reflexes, strength, and sensation only"]'::jsonb, 0, 'The GCS scores eye opening, verbal response, and motor response, with a total score ranging from 3 (deep coma) to 15 (fully alert).', 'Neurology', '🧠', true),
(3375, 'Neurology', 'AI Practice Question', 'Babinski''s sign, when positive (upgoing toe) in an adult, suggests:', '["A normal finding in all healthy adults", "Upper motor neuron pathology", "A peripheral nerve injury only", "No clinical significance"]'::jsonb, 1, 'A positive Babinski sign (extension of the big toe) in an adult indicates upper motor neuron dysfunction; it is a normal finding only in infants under about 2 years.', 'Neurology', '🧠', true),
(3376, 'Neurology', 'AI Practice Question', 'A subdural haematoma differs from an epidural haematoma primarily in that a subdural haematoma:', '["Is always caused by arterial bleeding with rapid deterioration", "Results from venous bleeding between the dura and arachnoid mater, often with a more gradual onset", "Never occurs after head trauma", "Always requires no treatment"]'::jsonb, 1, 'Subdural haematomas typically result from torn bridging veins (venous bleeding) with a more variable, sometimes gradual, presentation, unlike the classically rapid arterial epidural haematoma.', 'Neurology', '🧠', true),
(3377, 'Neurology', 'AI Practice Question', 'An epidural haematoma classically presents with:', '["Immediate, permanent coma with no lucid interval", "An initial loss of consciousness, a ''lucid interval,'' then rapid deterioration", "No relationship to head trauma", "Gradual onset over several weeks"]'::jsonb, 1, 'Classic epidural haematoma presentation includes initial LOC, a lucid interval as the patient appears to recover, followed by rapid deterioration as the haematoma expands — a neurosurgical emergency.', 'Neurology', '🧠', true),
(3378, 'Neurology', 'AI Practice Question', 'Deep tendon reflex testing assesses the integrity of the:', '["Cardiovascular system only", "Reflex arc, involving sensory input, spinal cord processing, and motor output", "Respiratory drive only", "Endocrine function"]'::jsonb, 1, 'Deep tendon reflexes test the reflex arc — sensory receptor, afferent nerve, spinal cord synapse, efferent nerve, and muscle response — assessing neurological integrity.', 'Neurology', '🧠', true),
(3379, 'Neurology Scenarios', 'AI Practice Question', 'A patient with a spinal cord injury at the T4 level develops sudden severe headache, profuse sweating above the injury level, and hypertension after bladder distension. This presentation is most consistent with:', '["Simple anxiety", "Autonomic dysreflexia, requiring identification and removal of the triggering stimulus", "Normal blood pressure response", "Hypoglycaemia"]'::jsonb, 1, 'Autonomic dysreflexia is a medical emergency in spinal cord injury above T6, often triggered by bladder/bowel distension, causing severe hypertension requiring urgent identification and removal of the trigger.', 'Neurology', '🧠', true),
(3380, 'Neurology', 'AI Practice Question', 'Meningeal signs such as nuchal rigidity and a positive Kernig''s sign are most associated with:', '["Simple tension headache", "Meningitis/meningeal irritation", "Migraine without complication", "Sinusitis"]'::jsonb, 1, 'Nuchal rigidity and positive Kernig''s/Brudzinski''s signs indicate meningeal irritation, classically seen in meningitis and requiring urgent evaluation.', 'Neurology', '🧠', true),
(3381, 'Neurology Scenarios', 'AI Practice Question', 'A patient recovering from a head injury is assessed to have decerebrate posturing (extension of all four limbs) in response to painful stimuli. This indicates:', '["A better prognosis than decorticate posturing", "More severe brainstem dysfunction, generally a worse prognosis than decorticate posturing", "Normal neurological function", "No clinical relevance"]'::jsonb, 1, 'Decerebrate (extensor) posturing indicates more severe brainstem involvement and generally carries a worse prognosis than decorticate (flexor) posturing.', 'Neurology', '🧠', true),
(3382, 'Neurology Scenarios', 'AI Practice Question', 'An unconscious patient''s airway is being protected. The nurse should recognise that airway reflexes (gag/cough) are typically lost when the GCS falls to approximately:', '["15", "12", "8 or below", "10, with no significance below this"]'::jsonb, 2, 'A GCS of 8 or below is the widely used threshold at which airway protective reflexes are considered unreliable, often prompting consideration of intubation (''GCS of 8, intubate'').', 'Neurology', '🧠', true),
(3383, 'Neurology Scenarios', 'AI Practice Question', 'A patient develops delirium in the ICU and non-pharmacological interventions have not been sufficient. The nurse understands that pharmacological management, if used, should:', '["Involve heavy, prolonged sedation as the default approach", "Be used cautiously and at the lowest effective dose, typically reserved for severe agitation posing safety risk", "Never be considered under any circumstances", "Always be started before non-pharmacological measures are tried"]'::jsonb, 1, 'Non-pharmacological strategies are first-line for delirium; pharmacological treatment is reserved for severe agitation posing a safety risk, used cautiously at the lowest effective dose.', 'Neurology', '🧠', true),
(3384, 'Neurology', 'AI Practice Question', 'Toxic Epidermal Necrolysis Syndrome (TEN), sometimes seen in critically ill patients, primarily involves:', '["A mild, self-limiting rash with no mucosal involvement", "Severe, widespread skin/mucosal detachment, often drug-induced, requiring burn-unit-level care", "A localised fungal skin infection", "A benign birthmark"]'::jsonb, 1, 'TEN is a severe, life-threatening mucocutaneous reaction (often drug-induced) causing widespread epidermal detachment, requiring specialised, often burn-unit-level supportive care.', 'Neurology', '🧠', true),
(3385, 'Renal Scenarios', 'AI Practice Question', 'A patient with acute kidney injury develops a serum potassium of 6.8mmol/L with peaked T-waves on ECG. The priority nursing action is to:', '["Wait for the next scheduled blood draw to confirm", "Alert the physician immediately and prepare for urgent treatment (e.g. calcium gluconate, insulin/dextrose)", "Encourage the patient to eat a banana", "Administer a potassium supplement"]'::jsonb, 1, 'Severe hyperkalaemia with ECG changes is a medical emergency requiring immediate treatment to stabilise the myocardium and shift potassium intracellularly.', 'Renal & Fluid Balance', '💧', true),
(3386, 'Renal Scenarios', 'AI Practice Question', 'A patient on haemodialysis develops hypotension, cramping, and nausea during the session. The nurse''s priority action is to:', '["Increase the ultrafiltration rate to relieve symptoms faster", "Slow or stop ultrafiltration, position the patient appropriately, and consider a fluid bolus per protocol", "Ignore symptoms since they are expected", "Immediately terminate dialysis access permanently"]'::jsonb, 1, 'Intradialytic hypotension is managed by reducing/stopping ultrafiltration, repositioning, and often giving a small fluid bolus, rather than escalating fluid removal.', 'Renal & Fluid Balance', '💧', true),
(3387, 'Renal Scenarios', 'AI Practice Question', 'A patient post-renal transplant develops decreased urine output, fever, and graft tenderness. The nurse should suspect:', '["Normal post-operative recovery", "Acute transplant rejection, requiring urgent evaluation", "Simple dehydration with no other cause", "Constipation"]'::jsonb, 1, 'Decreased urine output, fever and graft tenderness post-transplant are concerning for acute rejection and require urgent evaluation and reporting.', 'Renal & Fluid Balance', '💧', true),
(3388, 'Renal Scenarios', 'AI Practice Question', 'After renal transplant, the nurse monitors immunosuppressive drug levels (e.g. cyclosporine) closely, primarily because:', '["Levels have no clinical relevance", "Too low a level risks rejection, while too high a level risks toxicity/infection — a narrow therapeutic window must be maintained", "These drugs have no side effects at any dose", "Only the surgical team needs to know the levels"]'::jsonb, 1, 'Immunosuppressants have a narrow therapeutic window — sub-therapeutic levels risk rejection, while excessive levels increase toxicity and infection risk, requiring close monitoring.', 'Renal & Fluid Balance', '💧', true),
(3389, 'Renal Scenarios', 'AI Practice Question', 'A post-nephrectomy patient''s hourly urine output drops significantly with a rising heart rate and falling blood pressure. The nurse should first suspect:', '["Normal recovery with no action needed", "Hypovolaemia/bleeding, requiring urgent assessment and fluid resuscitation", "Overhydration", "A urinary tract infection"]'::jsonb, 1, 'Falling urine output with rising heart rate and falling blood pressure post-nephrectomy suggests hypovolaemia, potentially from bleeding, requiring urgent assessment.', 'Renal & Fluid Balance', '💧', true),
(3390, 'Renal Scenarios', 'AI Practice Question', 'A patient with severe dehydration shows dry mucous membranes, decreased skin turgor, and concentrated urine. The most appropriate initial nursing action is to:', '["Restrict all oral and IV fluids", "Initiate appropriate fluid replacement (oral or IV depending on severity) and monitor response", "Administer a diuretic", "Do nothing since these are normal findings"]'::jsonb, 1, 'Clinical signs of dehydration require prompt appropriate fluid replacement matched to severity, with ongoing monitoring of response.', 'Renal & Fluid Balance', '💧', true),
(3391, 'Renal Scenarios', 'AI Practice Question', 'A patient with chronic kidney disease develops signs of fluid overload — bilateral crackles, oedema, and elevated JVP. The nurse should anticipate management focused on:', '["Aggressive IV fluid administration", "Fluid restriction, diuretics (if some renal function remains) or ultrafiltration/dialysis, and sodium restriction", "Encouraging unlimited fluid intake", "Withholding all medications"]'::jsonb, 1, 'Fluid overload in CKD is managed with fluid/sodium restriction and diuretics or dialysis/ultrafiltration depending on residual renal function and severity.', 'Renal & Fluid Balance', '💧', true),
(3392, 'Renal', 'AI Practice Question', 'Continuous Renal Replacement Therapy (CRRT), compared to intermittent haemodialysis, is often preferred in haemodynamically unstable ICU patients because it:', '["Removes fluid/solutes more slowly and continuously, causing less haemodynamic stress", "Is always faster at removing toxins", "Requires no vascular access", "Has no risk of complications"]'::jsonb, 0, 'CRRT removes fluid and solutes gradually over 24 hours, causing less abrupt haemodynamic shift than intermittent dialysis, making it better tolerated in unstable patients.', 'Renal & Fluid Balance', '💧', true),
(3393, 'Renal', 'AI Practice Question', 'A common complication of Continuous Renal Replacement Therapy (CRRT) that requires close monitoring is:', '["Hypertension only", "Electrolyte imbalance and circuit clotting", "Hyperglycaemia exclusively, with no other risk", "Improved clotting with no bleeding risk"]'::jsonb, 1, 'CRRT carries risks of electrolyte disturbance from continuous filtration and circuit clotting (often requiring anticoagulation), both requiring vigilant monitoring.', 'Renal & Fluid Balance', '💧', true),
(3394, 'Renal Scenarios', 'AI Practice Question', 'A patient''s renal function tests show a rising creatinine and urea with oliguria following a major surgery complicated by hypotension. This presentation is most consistent with:', '["Chronic kidney disease of long standing", "Acute kidney injury, likely pre-renal from hypoperfusion", "Normal post-operative recovery", "Diabetes insipidus"]'::jsonb, 1, 'Rising creatinine/urea with oliguria after a hypotensive episode is characteristic of acute kidney injury, commonly pre-renal in origin from reduced renal perfusion.', 'Renal & Fluid Balance', '💧', true),
(3395, 'Renal', 'AI Practice Question', 'Daily weight is considered one of the most accurate indicators of a patient''s fluid balance because:', '["It reflects long-term nutritional status only", "Short-term weight changes closely track fluid gain or loss, more reliably than intake/output charting alone", "Weight has no relationship to fluid status", "It only matters for obese patients"]'::jsonb, 1, 'Daily weight is a highly sensitive and accurate marker of short-term fluid balance, often more reliable than intake/output charting alone, which can miss insensible losses.', 'Renal & Fluid Balance', '💧', true),
(3396, 'Renal Scenarios', 'AI Practice Question', 'A patient with severe burns is at risk of acute kidney injury primarily due to:', '["Excessive fluid intake only", "Hypovolaemia and myoglobin release from tissue damage causing renal tubular injury", "Overactive bladder", "Elevated haemoglobin"]'::jsonb, 1, 'Burns cause significant fluid loss (hypovolaemia) and myoglobin release from damaged tissue, both of which can injure the renal tubules and precipitate acute kidney injury.', 'Renal & Fluid Balance', '💧', true),
(3397, 'Renal', 'AI Practice Question', 'Apheresis, in the context of renal/critical care, refers to:', '["A surgical procedure to remove the kidney", "A procedure that separates and removes specific blood components (e.g. plasma) while returning the rest to the patient", "A type of dialysis catheter", "A urine collection method"]'::jsonb, 1, 'Apheresis separates blood components (e.g. plasma exchange), removing a targeted component while returning the remainder to the patient''s circulation.', 'Renal & Fluid Balance', '💧', true),
(3398, 'Renal Scenarios', 'AI Practice Question', 'A patient''s serum sodium is measured at 118mmol/L with confusion and lethargy. The nurse understands that correction of severe hyponatraemia must be done:', '["As rapidly as possible regardless of rate", "Gradually and carefully, since overly rapid correction risks osmotic demyelination syndrome", "Only with oral salt tablets, never IV", "With no monitoring required"]'::jsonb, 1, 'Severe hyponatraemia must be corrected gradually — overly rapid correction risks osmotic demyelination syndrome (central pontine myelinolysis), a serious neurological complication.', 'Renal & Fluid Balance', '💧', true),
(3399, 'Renal Scenarios', 'AI Practice Question', 'A patient with severe hypokalaemia (potassium 2.5mmol/L) is prescribed IV potassium replacement. The nurse''s priority safety consideration is to:', '["Give it as a rapid IV push for fastest correction", "Ensure it is properly diluted, infused slowly via pump, with continuous cardiac monitoring", "Give it intramuscularly instead", "Skip cardiac monitoring since potassium replacement is always safe"]'::jsonb, 1, 'IV potassium must always be diluted and infused slowly with cardiac monitoring, since rapid/undiluted administration risks fatal arrhythmias.', 'Renal & Fluid Balance', '💧', true),
(3400, 'Renal', 'AI Practice Question', 'The 4-2-1 rule for calculating maintenance IV fluid rate is based primarily on the patient''s:', '["Age only", "Body weight", "Blood pressure only", "Diagnosis only"]'::jsonb, 1, 'The 4-2-1 rule calculates maintenance fluid rate based on body weight in kilograms: 4ml/kg/hr for the first 10kg, 2ml/kg/hr for the next 10kg, and 1ml/kg/hr for each kg thereafter.', 'Renal & Fluid Balance', '💧', true),
(3401, 'Renal Scenarios', 'AI Practice Question', 'A patient with suspected acute urinary retention post-surgery has a palpable, distended bladder and reports lower abdominal discomfort with no voiding for 8 hours. The priority nursing action is to:', '["Encourage the patient to wait longer before intervening", "Assess bladder scan/volume and facilitate voiding or catheterisation as needed, per protocol", "Restrict all fluids", "Administer a laxative"]'::jsonb, 1, 'A distended, palpable bladder with inability to void suggests urinary retention requiring prompt assessment (e.g. bladder scan) and intervention such as catheterisation.', 'Renal & Fluid Balance', '💧', true),
(3402, 'Renal', 'AI Practice Question', 'Overhydration in a patient is most likely to present with:', '["Dry mucous membranes and poor skin turgor", "Bounding pulse, elevated blood pressure, and possible pulmonary crackles", "Concentrated, dark urine", "Tachycardia with hypotension"]'::jsonb, 1, 'Fluid overload typically presents with a bounding pulse, elevated blood pressure, and signs of pulmonary congestion such as crackles, reflecting excess intravascular volume.', 'Renal & Fluid Balance', '💧', true),
(3403, 'Renal Scenarios', 'AI Practice Question', 'A living-related kidney donor is being cared for post-nephrectomy. The nurse understands that outcomes for living-related transplants are generally:', '["Worse than cadaveric transplants", "Better than cadaveric transplants, both in short and long-term survival", "Identical to dialysis-alone outcomes", "Irrelevant to donor source"]'::jsonb, 1, 'Living-related kidney transplants generally have better graft and patient survival outcomes compared to cadaveric transplants, due to factors like better tissue matching and shorter ischaemia time.', 'Renal & Fluid Balance', '💧', true),
(3404, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient develops fever, tachycardia, tachypnoea, and hypotension not responding to an initial fluid bolus, with a known urinary tract infection. This presentation is most consistent with:', '["Simple dehydration", "Septic shock", "Cardiogenic shock", "Anxiety attack"]'::jsonb, 1, 'Fever with hypotension refractory to fluids in the setting of a known infection source is consistent with septic shock, requiring urgent sepsis bundle management.', 'Shock & Haemorrhage', '⚡', true),
(3405, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'The Surviving Sepsis ''hour-1 bundle'' includes which of the following priority actions?', '["Obtain blood cultures, measure lactate, give broad-spectrum antibiotics, and begin fluid resuscitation", "Wait for culture results before starting any treatment", "Give oral antibiotics only", "Delay fluids until blood pressure normalises spontaneously"]'::jsonb, 0, 'The hour-1 sepsis bundle emphasises rapid action: obtaining cultures and lactate, starting broad-spectrum antibiotics, and beginning fluid resuscitation — all without delay.', 'Shock & Haemorrhage', '⚡', true),
(3406, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A septic patient remains hypotensive despite adequate fluid resuscitation. The first-line vasopressor to initiate is:', '["Dobutamine", "Noradrenaline (norepinephrine)", "Furosemide", "Insulin"]'::jsonb, 1, 'Noradrenaline is the first-line vasopressor recommended for septic shock persisting despite adequate fluid resuscitation.', 'Shock & Haemorrhage', '⚡', true),
(3407, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A trauma patient with a systolic blood pressure of 85mmHg, heart rate 128, and cool clammy skin after a motor vehicle accident is most likely in which type of shock?', '["Cardiogenic shock", "Hypovolaemic shock", "Neurogenic shock", "Anaphylactic shock"]'::jsonb, 1, 'Tachycardia, hypotension, and cool clammy skin after trauma most strongly suggest hypovolaemic (haemorrhagic) shock from blood loss.', 'Shock & Haemorrhage', '⚡', true),
(3408, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient with a high spinal cord injury develops hypotension WITH bradycardia (rather than the expected compensatory tachycardia). This is most consistent with:', '["Hypovolaemic shock", "Neurogenic shock", "Septic shock", "Cardiogenic shock"]'::jsonb, 1, 'Neurogenic shock, from disrupted sympathetic tone after high spinal cord injury, is distinguished by hypotension with bradycardia rather than the tachycardia seen in most other shock types.', 'Shock & Haemorrhage', '⚡', true),
(3409, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient develops sudden hypotension, widespread urticaria, wheeze, and facial swelling shortly after receiving IV antibiotics. The immediate priority treatment is:', '["Oral antihistamine only", "Intramuscular adrenaline, alongside airway/breathing/circulation support", "Slowing the antibiotic infusion and observing", "Applying a cold compress only"]'::jsonb, 1, 'This presentation is anaphylaxis — IM adrenaline is the first-line, life-saving treatment, given without delay alongside ABC support.', 'Shock & Haemorrhage', '⚡', true),
(3410, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient with massive blood loss is receiving multiple units of blood products. The nurse should monitor closely for signs of:', '["Only allergic reaction, with no other concern", "Hypocalcaemia, hyperkalaemia, and coagulopathy from massive transfusion", "Improved clotting with no risk of complications", "Only hypoglycaemia"]'::jsonb, 1, 'Massive transfusion carries risks of citrate-induced hypocalcaemia, hyperkalaemia from stored blood, and dilutional coagulopathy, all requiring close monitoring.', 'Shock & Haemorrhage', '⚡', true),
(3411, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient in early (compensated) shock may show which finding, despite a normal blood pressure?', '["Bradycardia with warm, flushed skin", "Tachycardia, with normal blood pressure maintained by compensatory mechanisms", "Hypertension with bradycardia", "No clinical signs whatsoever"]'::jsonb, 1, 'In compensated shock, tachycardia and peripheral vasoconstriction maintain blood pressure temporarily — blood pressure can remain deceptively normal despite significant physiological compromise.', 'Shock & Haemorrhage', '⚡', true),
(3412, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'Blood loss replacement using crystalloid solution generally requires approximately how much volume relative to the estimated blood loss?', '["1:1 ratio (equal volume)", "3:1 ratio (three times the estimated blood loss)", "1:10 ratio", "No specific ratio applies"]'::jsonb, 1, 'Crystalloid solutions distribute across both intravascular and interstitial spaces, so roughly three times the estimated blood loss volume is needed to adequately replace intravascular volume (a 3:1 ratio), compared to a roughly 1:1 ratio for colloids/blood products.', 'Shock & Haemorrhage', '⚡', true),
(3413, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient with septic shock has a rising serum lactate despite fluid resuscitation. This finding is most concerning because it suggests:', '["Improved tissue perfusion", "Ongoing tissue hypoperfusion/anaerobic metabolism", "No clinical significance", "Resolved sepsis"]'::jsonb, 1, 'A persistently elevated or rising lactate reflects ongoing tissue hypoperfusion and anaerobic metabolism, indicating inadequate resuscitation and a worse prognosis if not corrected.', 'Shock & Haemorrhage', '⚡', true),
(3414, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient with multiple organ dysfunction syndrome (MODS) following sepsis requires nursing care primarily focused on:', '["A single-organ focus only, ignoring other systems", "Comprehensive, systematic monitoring and support of all affected organ systems", "No specific monitoring beyond routine vital signs", "Withholding all interventions"]'::jsonb, 1, 'MODS involves dysfunction across multiple organ systems, requiring comprehensive, systematic assessment and support (respiratory, cardiovascular, renal, hepatic, coagulation, neurological) rather than a single-system focus.', 'Shock & Haemorrhage', '⚡', true),
(3415, 'Shock & Sepsis Scenarios', 'AI Practice Question', 'A patient with obstructive shock from massive pulmonary embolism would be expected to show:', '["Low blood pressure with signs of right heart strain (e.g. elevated JVP) from obstructed pulmonary blood flow", "Warm, flushed skin with bounding pulses", "Bradycardia with normal blood pressure", "No cardiovascular compromise"]'::jsonb, 0, 'Massive PE causes obstructive shock — blood flow through the pulmonary circulation is physically obstructed, causing right heart strain, elevated JVP, and hypotension.', 'Shock & Haemorrhage', '⚡', true),
(3416, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with 40% total body surface area burns is being resuscitated using the Parkland formula. If the patient weighs 70kg, the total fluid requirement for the first 24 hours is calculated as:', '["4 x 70 x 40 = 11,200ml", "4 x 40 = 160ml", "70 x 40 = 2,800ml only", "No formula is used for burns"]'::jsonb, 0, 'The Parkland formula is 4ml x weight(kg) x %TBSA burned = total 24-hour fluid requirement; here 4 x 70 x 40 = 11,200ml, with half given in the first 8 hours.', 'Burns & Trauma', '🔥', true),
(3417, 'Burns & Trauma Scenarios', 'AI Practice Question', 'Using the Parkland formula, half of the calculated 24-hour fluid volume should be administered:', '["Evenly over the full 24 hours", "In the first 8 hours from the time of injury", "In the last 8 hours only", "As a single rapid bolus"]'::jsonb, 1, 'Half the calculated total is given in the first 8 hours (from time of injury, not time of arrival), with the remaining half over the following 16 hours.', 'Burns & Trauma', '🔥', true),
(3418, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with facial burns, singed nasal hair, and hoarseness of voice after a house fire should be closely monitored for:', '["No specific concern beyond the visible burns", "Inhalational airway injury, with high risk of rapid airway obstruction", "Simple anxiety", "Only skin infection risk"]'::jsonb, 1, 'Facial burns, singed nasal hair and hoarseness are red flags for inhalational injury, which can cause rapid, severe airway swelling — early intubation is often considered even before obvious respiratory distress.', 'Burns & Trauma', '🔥', true),
(3419, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with carbon monoxide poisoning from smoke inhalation should be treated with:', '["Room air only", "Humidified 100% oxygen", "No oxygen therapy is needed", "IV antibiotics as the primary treatment"]'::jsonb, 1, 'CO binds haemoglobin far more strongly than oxygen — humidified 100% oxygen displaces CO from haemoglobin and is the mainstay treatment for CO poisoning.', 'Burns & Trauma', '🔥', true),
(3420, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with an electrical burn injury passes dark, tea-coloured urine. The nurse should suspect:', '["A normal finding requiring no action", "Myoglobinuria from muscle breakdown, requiring aggressive fluid therapy and monitoring for acute kidney injury", "A urinary tract infection only", "Dehydration alone with no other significance"]'::jsonb, 1, 'Dark urine after electrical injury suggests myoglobinuria from rhabdomyolysis, which risks acute kidney injury and requires aggressive fluid resuscitation (sometimes with mannitol/bicarbonate).', 'Burns & Trauma', '🔥', true),
(3421, 'Burns & Trauma Scenarios', 'AI Practice Question', 'Following an electrical burn, the nurse should prioritise which monitoring, given the risk of delayed complications?', '["Skin colour only, with no other monitoring", "Continuous cardiac monitoring for at least 24–48 hours, given the risk of arrhythmias", "Blood glucose only", "No specific monitoring is required"]'::jsonb, 1, 'Electrical injuries carry a risk of cardiac arrhythmias that may be delayed, so continuous cardiac monitoring for 24–48 hours is standard practice.', 'Burns & Trauma', '🔥', true),
(3422, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient sustains a chemical burn from a strong acid. The immediate first-aid priority is to:', '["Apply a neutralising alkaline agent directly to the burn", "Irrigate copiously with water, avoiding neutralising agents which can generate additional heat/injury", "Apply ice directly to the burn", "Cover the wound tightly with an occlusive dressing immediately with no irrigation"]'::jsonb, 1, 'Chemical burns should be irrigated copiously with water — neutralising agents are avoided as the chemical reaction can generate additional heat and worsen tissue injury.', 'Burns & Trauma', '🔥', true),
(3423, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with frostbite to the fingers should be managed with:', '["Vigorous rubbing of the affected area to restore circulation", "Rapid rewarming in warm water (around 38–42°C), avoiding rubbing the frozen tissue", "Slow rewarming over several days", "Re-exposure to cold to ''toughen'' the tissue"]'::jsonb, 1, 'Frostbite is managed with rapid rewarming in warm water at 38–42°C; rubbing frozen tissue or re-exposing it to cold can cause further tissue damage.', 'Burns & Trauma', '🔥', true),
(3424, 'Burns & Trauma Scenarios', 'AI Practice Question', 'Using the Rule of Nines to estimate burn size in an adult, each entire arm represents approximately:', '["18% of total body surface area", "9% of total body surface area", "1% of total body surface area", "36% of total body surface area"]'::jsonb, 1, 'In the adult Rule of Nines, each arm represents approximately 9% of total body surface area.', 'Burns & Trauma', '🔥', true),
(3425, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A burns patient develops signs of sepsis on day 5 post-injury. The nurse understands this is significant because:', '["Sepsis is not a risk after the first 48 hours", "Sepsis is the leading cause of death in burns patients surviving the initial resuscitation phase (after 48 hours)", "Burns patients are never at risk of infection", "This is unrelated to the burn injury"]'::jsonb, 1, 'After surviving the initial 48-hour resuscitation phase, sepsis becomes the leading cause of death in burns patients due to compromised skin barrier and immune suppression.', 'Burns & Trauma', '🔥', true),
(3426, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with a compartment syndrome after a limb fracture develops severe pain out of proportion to the injury, pallor, and pain on passive stretch. The priority action is to:', '["Elevate the limb and apply ice, then reassess in 12 hours", "Urgently notify the physician, as this is a surgical emergency requiring prompt fasciotomy consideration", "Apply a tighter bandage for support", "Administer oral analgesia only and observe for 24 hours"]'::jsonb, 1, 'Compartment syndrome (5 Ps: pain, pallor, paraesthesia, pulselessness, pain on passive stretch) is a surgical emergency — delayed treatment risks permanent muscle/nerve damage, so urgent notification is essential.', 'Burns & Trauma', '🔥', true),
(3427, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with tetanus develops trismus (lockjaw) as an early symptom. The nurse understands this occurs because tetanus toxin:', '["Directly paralyses the diaphragm first", "Blocks inhibitory neurotransmitters (glycine and GABA), causing sustained, uncontrolled muscle contraction", "Causes generalised sedation", "Only affects the peripheral sensory nerves"]'::jsonb, 1, 'Tetanus toxin blocks inhibitory neurotransmission (glycine/GABA), removing the normal ''brakes'' on muscle contraction and causing sustained rigidity, classically starting with trismus.', 'Burns & Trauma', '🔥', true),
(3428, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A burns patient''s nutritional needs are significantly elevated. The nurse understands this is primarily because burns cause:', '["A decrease in metabolic rate", "A dramatic hypermetabolic response with increased caloric and protein requirements for wound healing", "No change in nutritional needs", "Only a temporary decrease in appetite with no metabolic change"]'::jsonb, 1, 'Major burns trigger a profound hypermetabolic state, dramatically increasing caloric and protein needs to support wound healing and combat catabolism.', 'Burns & Trauma', '🔥', true),
(3429, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with a decubitus (pressure) ulcer developing on the sacrum is best prevented from worsening by:', '["Leaving the patient in one position to avoid disturbing them", "Regular repositioning (e.g. every 2 hours), pressure-relieving surfaces, and skin assessment", "Applying tight, restrictive dressings only", "Restricting all mobility permanently"]'::jsonb, 1, 'Pressure ulcer prevention/management relies on regular repositioning, pressure-relieving surfaces, adequate nutrition, and routine skin assessment.', 'Burns & Trauma', '🔥', true),
(3430, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A family member of a critically injured trauma patient appears withdrawn, tearful, and repeatedly asks the same questions. The nurse''s most appropriate response is to:', '["Avoid the family entirely to prevent added stress", "Provide honest, consistent information, emotional support, and involve psychosocial resources as needed", "Tell the family nothing until the patient is discharged", "Dismiss their questions as unnecessary"]'::jsonb, 1, 'Family survival/coping support relies on honest, consistent communication, emotional support, and connecting families with appropriate psychosocial resources during a crisis.', 'Burns & Trauma', '🔥', true),
(3431, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A critically ill obese patient in the ICU requires special consideration primarily because obesity is associated with:', '["No additional risks compared to normal-weight patients", "Increased risks including difficult airway management, pressure injury, and altered drug dosing", "Only cosmetic concerns", "Reduced need for careful monitoring"]'::jsonb, 1, 'Obesity in critically ill patients increases risks around airway management, pressure injury, drug dosing/pharmacokinetics, and requires specific equipment/safety planning.', 'Burns & Trauma', '🔥', true),
(3432, 'Burns & Trauma', 'AI Practice Question', 'Abdominal Compartment Syndrome is defined by sustained intra-abdominal pressure elevation associated with:', '["No clinical consequences", "New organ dysfunction, commonly affecting renal, cardiovascular and respiratory systems", "Only mild abdominal discomfort", "Improved renal perfusion"]'::jsonb, 1, 'Abdominal Compartment Syndrome is sustained raised intra-abdominal pressure causing new organ dysfunction — commonly renal impairment, reduced venous return/cardiac output, and impaired ventilation.', 'Burns & Trauma', '🔥', true),
(3433, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with acute pancreatitis develops Grey Turner''s sign (flank bruising). This finding suggests:', '["A benign, unrelated skin condition", "Retroperitoneal haemorrhage, associated with severe pancreatitis", "Improved prognosis", "A localised allergic reaction"]'::jsonb, 1, 'Grey Turner''s sign (flank ecchymosis) reflects retroperitoneal bleeding and is associated with severe, haemorrhagic pancreatitis, a poor prognostic sign.', 'Burns & Trauma', '🔥', true),
(3434, 'Burns & Trauma Scenarios', 'AI Practice Question', 'A patient with severe acute pancreatitis is assessed using Ranson''s Criteria primarily to:', '["Diagnose the initial cause of pancreatitis", "Estimate disease severity and predict prognosis/mortality risk", "Determine surgical technique only", "Assess unrelated cardiac risk"]'::jsonb, 1, 'Ranson''s Criteria is a scoring system used to estimate severity and predict mortality risk in acute pancreatitis, guiding the intensity of monitoring and management.', 'Burns & Trauma', '🔥', true),
(3435, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with known oesophageal varices develops sudden haematemesis and hypotension. The nurse''s priority actions include:', '["Encourage oral fluids immediately", "Secure IV access, prepare for fluid/blood resuscitation, and avoid over-transfusion which can raise portal pressure", "Give a laxative to clear the bowel", "Discharge home with outpatient follow-up"]'::jsonb, 1, 'Variceal bleeding requires prompt resuscitation with IV access and blood products, but over-transfusion is avoided since it can raise portal pressure and worsen bleeding.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3436, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with fulminant hepatic failure develops worsening confusion and asterixis (flapping tremor). This presentation is most consistent with:', '["Simple fatigue", "Hepatic encephalopathy", "A normal finding with no significance", "Hypoglycaemia unrelated to liver disease"]'::jsonb, 1, 'Confusion with asterixis in a patient with liver failure is characteristic of hepatic encephalopathy, related to the liver''s reduced ability to clear ammonia.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3437, 'GI/Endocrine Scenarios', 'AI Practice Question', 'Lactulose is used in hepatic encephalopathy primarily to:', '["Increase ammonia absorption", "Trap ammonia in the colon as ammonium ions for excretion, lowering blood ammonia", "Treat bacterial infection directly", "Increase protein intake"]'::jsonb, 1, 'Lactulose acidifies the colon, converting ammonia (NH3) to ammonium (NH4+), which is poorly absorbed and excreted in stool, lowering blood ammonia levels.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3438, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with diabetic ketoacidosis (DKA) is started on an IV insulin infusion. The nurse should anticipate close monitoring of:', '["Only blood pressure", "Blood glucose and serum potassium, since insulin drives potassium into cells alongside glucose", "Only body temperature", "Only respiratory rate"]'::jsonb, 1, 'Insulin therapy in DKA can cause rapid drops in both glucose and potassium (as potassium shifts intracellularly), requiring frequent monitoring of both.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3439, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient in DKA presents with deep, rapid breathing (Kussmaul respirations) and a fruity breath odour. This reflects the body''s attempt to:', '["Compensate for metabolic acidosis by blowing off CO2", "Compensate for respiratory alkalosis", "Increase oxygen delivery with no relation to acid-base status", "Reduce blood glucose directly through breathing"]'::jsonb, 0, 'Kussmaul respirations are a compensatory response to the metabolic acidosis of DKA, with deep rapid breathing reducing CO2 to help raise pH; the fruity odour comes from exhaled ketones.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3440, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with Grave''s disease develops a thyroid storm — fever, severe tachycardia, and agitation. The priority management includes:', '["Withholding all treatment until the crisis resolves spontaneously", "Antithyroid medication, beta-blockade, cooling measures, and treatment of any precipitating factor", "Only reassurance and no active treatment", "Immediate thyroidectomy in the emergency department"]'::jsonb, 1, 'Thyroid storm is a life-threatening emergency requiring prompt antithyroid drugs, beta-blockade for symptom control, active cooling, and identification/treatment of the precipitating cause.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3441, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient six hours post-thyroidectomy develops increasing neck swelling and stridor. The nurse''s priority action is to:', '["Reassure the patient this is normal post-operative swelling with no action needed", "Call for immediate help, sit the patient upright, give high-flow oxygen, and prepare for emergency wound release if instructed", "Apply a tight neck dressing to control swelling", "Discharge the patient home for outpatient follow-up"]'::jsonb, 1, 'Post-thyroidectomy airway compression from a wound haematoma is a life-threatening emergency requiring immediate escalation and, if instructed, bedside opening of the wound to release the haematoma.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3442, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient post-thyroidectomy develops perioral tingling and a positive Chvostek''s sign. This suggests:', '["Normal recovery with no concern", "Hypocalcaemia from parathyroid gland disturbance during surgery", "Hyperkalaemia", "A wound infection"]'::jsonb, 1, 'Perioral tingling and a positive Chvostek''s sign suggest hypocalcaemia, a recognised complication when the parathyroid glands are disturbed during thyroid surgery.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3443, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A critically ill patient receiving total parenteral nutrition (TPN) should be monitored closely for:', '["No specific complications, since TPN is risk-free", "Catheter-related sepsis, hyperglycaemia, and electrolyte disturbances", "Only weight gain, with no other concern", "Improved liver function with no monitoring needed"]'::jsonb, 1, 'TPN carries risks including catheter-related bloodstream infection, hyperglycaemia, and electrolyte imbalances, all requiring vigilant monitoring.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3444, 'GI/Endocrine Scenarios', 'AI Practice Question', 'Enteral nutrition is generally preferred over parenteral nutrition in a critically ill patient with a functioning gut, primarily because enteral feeding:', '["Has no advantages over parenteral nutrition", "Maintains gut mucosal integrity, reduces infection risk, and is more physiological", "Always requires central venous access", "Cannot be given to any critically ill patient"]'::jsonb, 1, 'Enteral nutrition preserves gut mucosal integrity, helps maintain the gut immune barrier, and carries a lower infection risk compared to parenteral nutrition — ''if the gut works, use it.''', 'GI, Endocrine & Metabolic', '🍽️', true),
(3445, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A malnourished patient begins aggressive enteral feeding and develops sudden hypophosphataemia, hypokalaemia, and cardiac arrhythmia. The nurse should recognise this as:', '["A normal, expected response to feeding", "Refeeding syndrome, requiring slow reintroduction of nutrition and electrolyte correction", "An allergic reaction to the feed", "Unrelated to nutritional status"]'::jsonb, 1, 'Refeeding syndrome occurs when nutrition is reintroduced too quickly in a malnourished patient, causing dangerous electrolyte shifts (especially phosphate) — feeding must be reintroduced slowly with close monitoring.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3446, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with severe acute pancreatitis has hypocalcaemia. This is primarily explained by:', '["Excess dietary calcium intake", "Calcium being consumed in saponification (fat necrosis) reactions within the abdomen", "A pre-existing unrelated condition", "Overactive parathyroid glands"]'::jsonb, 1, 'In severe pancreatitis, released pancreatic enzymes cause fat necrosis, and calcium is consumed in the resulting saponification process, contributing to hypocalcaemia.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3447, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient''s symptoms of polydipsia, polyuria, and polyphagia in the context of newly elevated blood glucose most strongly suggest:', '["Diabetes insipidus", "Diabetes mellitus", "Simple dehydration unrelated to glucose", "Chronic kidney disease"]'::jsonb, 1, 'The classic triad of polydipsia, polyuria and polyphagia with elevated blood glucose is characteristic of diabetes mellitus.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3448, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with acute hepatic failure requires monitoring for coagulopathy primarily because:', '["The liver has no role in clotting factor production", "The liver synthesises most clotting factors, so failure impairs coagulation and increases bleeding risk", "Coagulopathy never occurs in liver disease", "Only platelets are affected, never clotting factors"]'::jsonb, 1, 'The liver produces most clotting factors; hepatic failure impairs this synthesis, causing coagulopathy and increased bleeding risk requiring close monitoring.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3449, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with severe hyperglycaemic hyperosmolar state (HHS) typically presents with profound dehydration and altered mental status, but WITHOUT the significant ketosis seen in DKA. This is because HHS occurs in a setting of:', '["Complete absence of any circulating insulin", "Some residual insulin production, sufficient to suppress significant ketogenesis but not to prevent severe hyperglycaemia", "Excess insulin administration", "No relationship to blood glucose"]'::jsonb, 1, 'HHS (typically in type 2 diabetes) occurs with enough residual insulin to suppress marked ketogenesis, but not enough to control severe hyperglycaemia, distinguishing it from DKA.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3450, 'Obstetric Scenarios', 'AI Practice Question', 'A pregnant patient at 32 weeks presents with painless, bright red vaginal bleeding. This presentation is most concerning for:', '["Placental abruption", "Placenta praevia", "Normal spotting in pregnancy", "Round ligament pain"]'::jsonb, 1, 'Painless bright red bleeding in later pregnancy is classic for placenta praevia, whereas placental abruption typically presents with painful bleeding.', 'Obstetric & Neonatal', '🤱', true),
(3451, 'Obstetric Scenarios', 'AI Practice Question', 'A pregnant patient presents with severe, constant abdominal pain, a tense/rigid uterus, and dark vaginal bleeding. This presentation is most concerning for:', '["Placenta praevia", "Placental abruption", "Braxton Hicks contractions", "Normal labour onset"]'::jsonb, 1, 'Painful bleeding with uterine rigidity/tenderness is characteristic of placental abruption, an obstetric emergency threatening both mother and fetus.', 'Obstetric & Neonatal', '🤱', true),
(3452, 'Obstetric Scenarios', 'AI Practice Question', 'A woman in the third trimester develops sudden severe headache, visual disturbance, and blood pressure of 165/110mmHg with proteinuria. The nurse should recognise this as warning signs of impending:', '["Normal pregnancy discomfort", "Eclamptic seizure", "Simple migraine unrelated to pregnancy", "Round ligament strain"]'::jsonb, 1, 'Severe headache and visual disturbance in a hypertensive, proteinuric pregnant patient are classic warning signs that a seizure (eclampsia) may be imminent.', 'Obstetric & Neonatal', '🤱', true),
(3453, 'Obstetric Scenarios', 'AI Practice Question', 'A postpartum patient develops sudden hypotension, hypoxia, and disseminated intravascular coagulation shortly after a difficult delivery. This presentation should raise suspicion for:', '["Simple postpartum fatigue", "Amniotic fluid embolism", "Normal blood loss from delivery", "Mastitis"]'::jsonb, 1, 'The triad of hypotension, hypoxia, and DIC around the time of delivery is classic for amniotic fluid embolism, a rare but often fatal obstetric emergency.', 'Obstetric & Neonatal', '🤱', true),
(3454, 'Obstetric Scenarios', 'AI Practice Question', 'A patient with postpartum haemorrhage has a soft, boggy uterus on palpation. The most likely cause, according to the ''4 Ts'' framework, is:', '["Trauma", "Tone (uterine atony)", "Tissue (retained placenta)", "Thrombin (coagulopathy)"]'::jsonb, 1, 'A soft, boggy (atonic) uterus is the classic finding of uterine atony (''Tone''), the most common cause of postpartum haemorrhage.', 'Obstetric & Neonatal', '🤱', true),
(3455, 'Obstetric Scenarios', 'AI Practice Question', 'The initial nursing management of uterine atony causing postpartum haemorrhage includes:', '["Firm fundal massage and administration of uterotonic medication (e.g. oxytocin) as prescribed", "Withholding all intervention until bleeding stops spontaneously", "Immediate hysterectomy without trying conservative measures first", "Applying ice to the abdomen only"]'::jsonb, 0, 'Uterine atony is initially managed with fundal massage to stimulate contraction and uterotonic drugs (e.g. oxytocin) to help the uterus contract and control bleeding.', 'Obstetric & Neonatal', '🤱', true),
(3456, 'Obstetric Scenarios', 'AI Practice Question', 'A pregnant patient with severe hyperemesis gravidarum is at risk of thiamine deficiency, which can cause:', '["No neurological consequences", "Wernicke''s encephalopathy", "Improved neurological function", "Only mild fatigue with no other risk"]'::jsonb, 1, 'Prolonged vomiting in hyperemesis gravidarum can deplete thiamine stores, risking Wernicke''s encephalopathy — thiamine replacement is important, especially before glucose administration.', 'Obstetric & Neonatal', '🤱', true),
(3457, 'Obstetric Scenarios', 'AI Practice Question', 'A patient with severe pre-eclampsia is started on magnesium sulfate. Before each dose/during the infusion, the nurse must assess:', '["Only blood glucose", "Deep tendon reflexes, respiratory rate, and urine output (''TRU'')", "Only skin colour", "Only pain score"]'::jsonb, 1, 'Magnesium sulfate toxicity is monitored using ''TRU'' — Tendon reflexes, Respiratory rate, and Urine output — checked regularly during the infusion.', 'Obstetric & Neonatal', '🤱', true),
(3458, 'Obstetric Scenarios', 'AI Practice Question', 'A Rhesus-negative mother delivers a Rhesus-positive baby. The nurse anticipates administration of:', '["No specific treatment is needed", "Anti-D immunoglobulin to the mother to prevent sensitisation in future pregnancies", "Anti-D immunoglobulin to the baby", "Oxytocin to the mother for this purpose"]'::jsonb, 1, 'Anti-D immunoglobulin is given to Rh-negative mothers after delivery of an Rh-positive baby to prevent maternal sensitisation, which could cause haemolytic disease in future pregnancies.', 'Obstetric & Neonatal', '🤱', true),
(3459, 'Obstetric Scenarios', 'AI Practice Question', 'A patient in labour has premature rupture of membranes with meconium-stained liquor. This finding is significant because it may indicate:', '["A completely normal, reassuring finding with no significance", "Possible fetal distress, requiring closer fetal monitoring", "Definite fetal death, requiring no further action", "A sign of maternal infection only"]'::jsonb, 1, 'Meconium-stained liquor can indicate fetal distress and requires closer fetal monitoring and preparation for potential neonatal complications at delivery.', 'Obstetric & Neonatal', '🤱', true),
(3460, 'Obstetric Scenarios', 'AI Practice Question', 'A newborn requires resuscitation immediately after birth and is not breathing adequately. The priority initial action is to:', '["Wait several minutes before intervening", "Dry, stimulate, and position the airway, then provide positive pressure ventilation if breathing remains inadequate", "Immediately begin chest compressions before assessing breathing", "Give oxygen by face mask only, with no other assessment"]'::jsonb, 1, 'Neonatal resuscitation begins with drying/stimulating and positioning the airway; if breathing remains inadequate, positive pressure ventilation is the priority next step before considering compressions.', 'Obstetric & Neonatal', '🤱', true),
(3461, 'Obstetric Scenarios', 'AI Practice Question', 'A premature neonate develops signs of respiratory distress shortly after birth, including grunting, nasal flaring, and chest retractions. This is most consistent with:', '["Normal newborn breathing pattern", "Respiratory distress syndrome from surfactant deficiency", "A congenital heart defect exclusively", "Overfeeding"]'::jsonb, 1, 'Grunting, nasal flaring and retractions in a premature neonate are classic signs of respiratory distress syndrome, related to surfactant deficiency in immature lungs.', 'Obstetric & Neonatal', '🤱', true),
(3462, 'Obstetric Scenarios', 'AI Practice Question', 'A neonate develops jaundice within the first 24 hours of life. The nurse should recognise this as:', '["Normal physiological jaundice requiring no evaluation", "Pathological jaundice requiring urgent evaluation, since it appears earlier than typical physiological jaundice", "Always due to breastfeeding alone", "Never clinically significant"]'::jsonb, 1, 'Jaundice appearing within the first 24 hours of life is considered pathological (unlike the more common physiological jaundice appearing after day 2–3) and requires urgent evaluation.', 'Obstetric & Neonatal', '🤱', true),
(3463, 'Obstetric Scenarios', 'AI Practice Question', 'A cervical incompetence diagnosis in a pregnant patient primarily increases the risk of:', '["Post-term pregnancy", "Second-trimester pregnancy loss or preterm birth from painless cervical dilation", "Gestational diabetes", "Multiple pregnancy"]'::jsonb, 1, 'Cervical incompetence involves painless cervical dilation, typically in the second trimester, increasing the risk of pregnancy loss or preterm birth.', 'Obstetric & Neonatal', '🤱', true),
(3464, 'Obstetric Scenarios', 'AI Practice Question', 'A woman with an ectopic pregnancy presents with unilateral lower abdominal pain, vaginal bleeding, and signs of hypovolaemic shock. This presentation should be treated as:', '["A routine outpatient concern", "A life-threatening gynaecological emergency requiring urgent assessment and likely surgical intervention", "Normal early pregnancy discomfort", "A urinary tract infection"]'::jsonb, 1, 'A ruptured ectopic pregnancy is a life-threatening cause of intra-abdominal haemorrhage and hypovolaemic shock, requiring urgent surgical management.', 'Obstetric & Neonatal', '🤱', true),
(3465, 'Infection Prevention Scenarios', 'AI Practice Question', 'A patient on a mechanical ventilator develops new fever, purulent secretions, and a new infiltrate on chest X-ray after 4 days of ventilation. This presentation is most consistent with:', '["Normal expected findings on a ventilator", "Ventilator-Associated Pneumonia (VAP)", "Simple atelectasis with no infection", "Pulmonary embolism"]'::jsonb, 1, 'New fever, purulent secretions and a new infiltrate after several days of mechanical ventilation are classic diagnostic features of VAP.', 'Infection Prevention', '🦠', true),
(3466, 'Infection Prevention Scenarios', 'AI Practice Question', 'A patient with a central line in place for 10 days develops fever with no other obvious source. The nurse should suspect:', '["The central line as a possible source and should assess/report per protocol (e.g. CLABSI workup)", "No relationship to the central line whatsoever", "A skin allergy to the dressing only", "Nothing requiring further action"]'::jsonb, 0, 'Unexplained fever in a patient with a central line should raise suspicion for CLABSI, prompting assessment of the line, cultures, and physician notification.', 'Infection Prevention', '🦠', true),
(3467, 'Infection Prevention Scenarios', 'AI Practice Question', 'According to WHO''s 5 Moments of Hand Hygiene, hand hygiene should be performed:', '["Only before touching a patient", "Before touching a patient, before a clean/aseptic procedure, after body fluid exposure risk, after touching a patient, and after touching patient surroundings", "Only after visibly soiled hands", "Only once per shift"]'::jsonb, 1, 'WHO''s 5 Moments define the key points during patient care where hand hygiene is essential: before patient contact, before aseptic procedures, after fluid exposure risk, after patient contact, and after touching surroundings.', 'Infection Prevention', '🦠', true),
(3468, 'Infection Prevention Scenarios', 'AI Practice Question', 'A patient with suspected active pulmonary tuberculosis is admitted to a general ward by mistake. The priority nursing action is to:', '["Leave the patient where they are with no changes", "Move the patient to a negative-pressure isolation room and initiate airborne precautions with N95 respirators for staff", "Simply close the patient''s door with no other change", "Discharge the patient immediately"]'::jsonb, 1, 'Suspected active TB requires prompt transfer to airborne (negative-pressure) isolation with fit-tested N95 respirator use by staff, given its airborne transmission route.', 'Infection Prevention', '🦠', true),
(3469, 'Infection Prevention Scenarios', 'AI Practice Question', 'A severely neutropenic chemotherapy patient is admitted. The nurse should implement:', '["Standard barrier nursing to protect other patients from this patient", "Reverse barrier nursing (protective isolation) to protect this patient from external pathogens", "No special precautions are needed", "Airborne precautions specifically for the patient''s own protection, with no other measures"]'::jsonb, 1, 'A severely immunocompromised patient needs reverse barrier nursing (protective isolation) to shield them from external pathogens, the opposite goal of standard source isolation.', 'Infection Prevention', '🦠', true),
(3470, 'Infection Prevention Scenarios', 'AI Practice Question', 'The correct order for donning personal protective equipment before entering an isolation room is:', '["Gloves, mask, gown, hand hygiene", "Hand hygiene, gown, mask, goggles, gloves", "Mask, gloves, gown, hand hygiene", "Goggles, gown, hand hygiene, gloves, mask"]'::jsonb, 1, 'Standard donning sequence is hand hygiene first, then gown, mask, goggles/eye protection, and gloves last, ensuring the most contamination-prone items (gloves) go on last.', 'Infection Prevention', '🦠', true),
(3471, 'Infection Prevention Scenarios', 'AI Practice Question', 'When removing (doffing) PPE after caring for an isolated patient, the correct order is:', '["Gloves, goggles, gown, mask, hand hygiene", "Mask first, then gloves, then gown", "Hand hygiene only, with no specific PPE removal order", "Gown first, followed immediately by mask with no hand hygiene between"]'::jsonb, 0, 'PPE doffing removes the most contaminated items first: gloves, then goggles, then gown, then mask, with hand hygiene performed at the end (and often between steps).', 'Infection Prevention', '🦠', true),
(3472, 'Infection Prevention Scenarios', 'AI Practice Question', 'A patient with a urinary catheter in place for a prolonged period without clear ongoing indication should prompt the nurse to:', '["Leave the catheter in place indefinitely since it is already inserted", "Assess ongoing necessity daily and advocate for prompt removal if no longer clinically indicated, to reduce CAUTI risk", "Increase catheter irrigation frequency to prevent infection", "Ignore duration since catheters carry no infection risk"]'::jsonb, 1, 'Daily assessment of catheter necessity and prompt removal when no longer needed is a core CAUTI prevention strategy — prolonged unnecessary catheterisation significantly raises infection risk.', 'Infection Prevention', '🦠', true),
(3473, 'Infection Prevention Scenarios', 'AI Practice Question', 'A patient develops signs of sepsis with an unknown source. Blood cultures are drawn from two different sites before starting antibiotics. This practice is done primarily to:', '["Delay treatment unnecessarily", "Improve the diagnostic yield and help distinguish true bacteraemia from contamination", "Reduce patient discomfort", "Save laboratory costs"]'::jsonb, 1, 'Drawing blood cultures from two separate sites before antibiotics improves the chance of identifying the causative organism and helps differentiate a true pathogen from a skin contaminant.', 'Infection Prevention', '🦠', true),
(3474, 'Infection Prevention', 'AI Practice Question', 'ICU patients are disproportionately affected by healthcare-associated infections mainly because of:', '["Lower exposure to invasive devices compared to general wards", "Higher exposure to invasive devices (lines, catheters, ventilators), impaired immunity, and prolonged hospital stay", "No particular increased risk compared to other wards", "Better infection control than general wards, paradoxically increasing risk"]'::jsonb, 1, 'ICU patients have disproportionately high rates of HAI due to extensive invasive device use, critical illness-related immune impairment, and often prolonged hospitalisation.', 'Infection Prevention', '🦠', true),
(3475, 'Infection Prevention Scenarios', 'AI Practice Question', 'A necrotising soft tissue infection patient requires urgent surgical debridement in addition to antibiotics. The nurse understands antibiotics alone are insufficient because:', '["Antibiotics have no role at all in this condition", "Necrotic, poorly perfused tissue limits antibiotic penetration, so infected/dead tissue must be surgically removed", "Surgery is only needed for cosmetic reasons", "Antibiotics work better without any surgical intervention"]'::jsonb, 1, 'Necrotic tissue has poor blood supply, limiting antibiotic penetration — surgical debridement of dead/infected tissue is essential alongside systemic antibiotics.', 'Infection Prevention', '🦠', true),
(3476, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient receiving a noradrenaline infusion via a peripheral IV develops swelling, pain, and blanching at the insertion site. The nurse should suspect:', '["Normal, expected finding requiring no action", "Extravasation, requiring the infusion to be stopped, the physician notified, and antidote/local treatment considered per protocol", "An allergic reaction requiring more noradrenaline", "Simply that the IV needs a faster flow rate"]'::jsonb, 1, 'Extravasation of a potent vasoconstrictor like noradrenaline can cause severe local tissue injury/necrosis — it must be recognised promptly and managed per protocol (often including phentolamine as an antidote).', 'ICU Pharmacology', '💊', true),
(3477, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient on a heparin infusion has an aPTT significantly above the therapeutic target range, with new bruising. The nurse should anticipate:', '["Increasing the heparin rate further", "Reducing or stopping the infusion per protocol and preparing protamine sulfate if reversal is needed", "No action, since bruising is expected and irrelevant", "Switching immediately to oral warfarin with no bridging"]'::jsonb, 1, 'An excessively elevated aPTT with bleeding signs indicates over-anticoagulation — the infusion should be adjusted/stopped per protocol, with protamine sulfate available if urgent reversal is needed.', 'ICU Pharmacology', '💊', true),
(3478, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient develops signs of digoxin toxicity — nausea, visual disturbances, and new arrhythmia. The nurse should also check for a contributing electrolyte abnormality, specifically:', '["Hypercalcaemia", "Hypokalaemia, which increases sensitivity to digoxin toxicity", "Hypernatraemia", "Hyperglycaemia"]'::jsonb, 1, 'Hypokalaemia increases myocardial sensitivity to digoxin, precipitating toxicity even at therapeutic digoxin levels — checking and correcting potassium is essential.', 'ICU Pharmacology', '💊', true),
(3479, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient sedated with a continuous propofol infusion for several days develops metabolic acidosis, rhabdomyolysis, and cardiac dysfunction. The nurse should suspect:', '["Normal, expected sedative effect with no concern", "Propofol Infusion Syndrome, a rare but serious complication of prolonged high-dose propofol use", "A simple allergic reaction to propofol", "Improved sedation with no adverse effect"]'::jsonb, 1, 'Propofol Infusion Syndrome is a rare, serious complication associated with prolonged high-dose propofol use, presenting with metabolic acidosis, rhabdomyolysis, and cardiac dysfunction.', 'ICU Pharmacology', '💊', true),
(3480, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient receiving IV vancomycin develops flushing, a rash on the upper body, and hypotension shortly after the infusion starts. This presentation is most consistent with:', '["A true IgE-mediated anaphylactic reaction only", "''Red man syndrome,'' related to rapid infusion rate rather than true allergy in many cases", "Normal expected drug effect requiring no action", "Sepsis unrelated to the medication"]'::jsonb, 1, '''Red man syndrome'' is a histamine-release reaction often related to rapid vancomycin infusion, managed by slowing the infusion rate and supportive care, distinct from a true IgE-mediated allergy.', 'ICU Pharmacology', '💊', true),
(3481, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient on long-term corticosteroid therapy for a chronic condition is admitted critically ill. The nurse should anticipate the need for:', '["Abrupt discontinuation of steroids immediately", "Continued (often increased ''stress-dose'') steroid coverage, since abrupt withdrawal risks adrenal crisis", "No special consideration regarding steroid dosing", "Switching immediately to an unrelated drug class"]'::jsonb, 1, 'Patients on long-term steroids have suppressed adrenal function — abrupt withdrawal during acute illness risks adrenal crisis, so continued (often stress-dose) steroid coverage is needed.', 'ICU Pharmacology', '💊', true),
(3482, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient is prescribed IV magnesium sulfate for severe asthma unresponsive to initial bronchodilators. The nurse should administer this:', '["As a rapid undiluted IV push", "As a slow IV infusion (e.g. over about 20 minutes), monitoring for hypotension", "Intramuscularly only", "Only after 24 hours of no improvement"]'::jsonb, 1, 'IV magnesium sulfate for severe asthma is given as a slow infusion (commonly over about 20 minutes) with monitoring, as rapid administration risks hypotension and other adverse effects.', 'ICU Pharmacology', '💊', true),
(3483, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A critically ill patient''s family insists on a treatment the medical team believes is futile and potentially harmful. The nurse''s most appropriate initial role is to:', '["Immediately refuse to provide any further care", "Facilitate open communication between the family and the care team, involving ethics consultation if needed", "Side entirely with the family regardless of clinical judgement", "Make the final treatment decision independently as the nurse"]'::jsonb, 1, 'The nurse''s role in ethical conflicts is to facilitate communication and understanding between family and team, escalating to formal ethics consultation when needed — not to unilaterally decide or refuse care.', 'Ethics, Law & Management', '⚖️', true),
(3484, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A nurse discovers a colleague made a significant medication error that was not reported. The most appropriate action is to:', '["Say nothing to avoid conflict with the colleague", "Ensure the patient is assessed/safe, and ensure the error is properly reported through the appropriate incident reporting channel", "Report the colleague to the police immediately", "Correct the error silently with no documentation"]'::jsonb, 1, 'Patient safety comes first (assessment for harm), followed by proper incident reporting through institutional channels — this supports learning and safety, not punitive action or silence.', 'Ethics, Law & Management', '⚖️', true),
(3485, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A conscious, competent adult patient refuses a blood transfusion on religious grounds despite life-threatening anaemia. The nurse''s ethically and legally appropriate response is to:', '["Administer the transfusion anyway, since the situation is life-threatening", "Respect the patient''s autonomous refusal after ensuring they are fully informed, and document thoroughly", "Have a family member override the patient''s decision", "Discharge the patient immediately with no further care"]'::jsonb, 1, 'A competent adult''s informed refusal of treatment must be respected, even when life-threatening — the nurse ensures the patient understands the risks and documents the refusal thoroughly.', 'Ethics, Law & Management', '⚖️', true),
(3486, 'Management Scenarios', 'AI Practice Question', 'During a mass casualty event, the charge nurse must delegate tasks rapidly to a team with mixed experience levels. The most appropriate delegation approach is to:', '["Assign tasks randomly with no regard for skill level", "Match tasks to each team member''s competency level, ensuring appropriate supervision for less experienced staff", "Assign only the most complex tasks to the least experienced staff", "Refuse to delegate anything and do all tasks personally"]'::jsonb, 1, 'Effective delegation, especially under crisis conditions, matches task complexity to staff competency, with appropriate supervision for less experienced team members.', 'Ethics, Law & Management', '⚖️', true),
(3487, 'Management Scenarios', 'AI Practice Question', 'A new nurse on the unit repeatedly makes documentation errors despite initial teaching. The nurse manager''s most constructive approach is to:', '["Publicly criticise the nurse in front of colleagues", "Provide targeted, private feedback, additional focused training, and follow institutional progressive improvement processes", "Terminate employment immediately without any improvement plan", "Ignore the errors to avoid conflict"]'::jsonb, 1, 'Constructive performance management uses private feedback, targeted training, and a structured, progressive improvement process rather than public criticism or immediate termination.', 'Ethics, Law & Management', '⚖️', true),
(3488, 'Research Scenarios', 'AI Practice Question', 'A nurse wants to implement a new evidence-based practice change on the unit based on a research finding. The most appropriate first step is to:', '["Implement the change immediately unit-wide with no evaluation", "Critically appraise the evidence, involve relevant stakeholders, and consider a structured pilot with evaluation before wider rollout", "Ignore the research since current practice has always worked", "Implement changes based on personal opinion alone, without reference to evidence"]'::jsonb, 1, 'Evidence-based practice change requires critical appraisal of the evidence, stakeholder involvement, and typically a piloted, evaluated rollout rather than an immediate, unevaluated unit-wide change.', 'Research & Nursing Process', '📊', true),
(3489, 'Research', 'AI Practice Question', 'A researcher wants to test whether a new positioning technique reduces pressure ulcer incidence. The dependent variable in this study would be:', '["The positioning technique used", "Pressure ulcer incidence, since it is the outcome being measured", "The patient''s age", "The researcher''s experience level"]'::jsonb, 1, 'The dependent variable is the outcome measured (pressure ulcer incidence), which is expected to change based on the independent variable (the positioning technique).', 'Research & Nursing Process', '📊', true),
(3490, 'Research', 'AI Practice Question', 'Informed consent in a research study must include disclosure of:', '["Only the study''s expected benefits, omitting risks", "The purpose, procedures, risks, benefits, and the participant''s right to withdraw at any time without penalty", "Only the researcher''s name", "No disclosure is required if the study is anonymous"]'::jsonb, 1, 'Research informed consent requires full disclosure of purpose, procedures, risks, benefits, and the right to withdraw without penalty, consistent with core research ethics principles.', 'Research & Nursing Process', '📊', true),
(3491, 'Nursing Process Scenarios', 'AI Practice Question', 'A nurse develops a care plan with the goal ''Patient will ambulate 50 metres independently by discharge.'' At reassessment, the patient can walk 30 metres with assistance. This goal should be documented as:', '["Fully met", "Partially met, requiring plan revision", "Not applicable", "Completely unmet with no progress"]'::jsonb, 1, 'Partial progress toward but not achieving the stated goal is documented as ''partially met,'' prompting reassessment and revision of the care plan.', 'Research & Nursing Process', '📊', true),
(3492, 'Nursing Process', 'AI Practice Question', 'During the ''Implementation'' phase of the nursing process, the nurse is primarily focused on:', '["Only writing the initial assessment", "Carrying out the planned interventions and continuing to collect data on the patient''s response", "Only evaluating final outcomes", "Only formulating the nursing diagnosis"]'::jsonb, 1, 'Implementation involves carrying out the planned nursing interventions while continuing ongoing data collection on the patient''s response, distinct from assessment, diagnosis or final evaluation.', 'Research & Nursing Process', '📊', true),
(3493, 'Physiotherapy Scenarios (CCN 425)', 'AI Practice Question', 'A ventilated patient has thick, retained secretions despite suctioning. The physiotherapist recommends postural drainage combined with percussion. The nurse''s role during this session includes:', '["Leaving the room during the procedure", "Monitoring vital signs, oxygen saturation, and haemodynamic stability throughout, and stopping if the patient becomes unstable", "Administering sedation to keep the patient still with no monitoring", "Disconnecting the ventilator for the entire session"]'::jsonb, 1, 'The nurse''s role during chest physiotherapy includes continuous monitoring for physiological tolerance, ready to pause or stop the session if the patient becomes haemodynamically or respiratory unstable.', 'Rehabilitation & Mobilization', '🏃', true),
(3494, 'Physiotherapy Scenarios (CCN 425)', 'AI Practice Question', 'A patient with a flail chest and multiple rib fractures is a candidate for chest physiotherapy, but the nurse should be cautious about which technique specifically?', '["Deep breathing exercises", "Percussion, given the risk of further rib injury", "Incentive spirometry", "Positioning changes in general"]'::jsonb, 1, 'Percussion is generally avoided or used cautiously over fractured ribs/flail segments due to the risk of worsening the injury.', 'Rehabilitation & Mobilization', '🏃', true),
(3495, 'Physiotherapy Scenarios (CCN 425)', 'AI Practice Question', 'A ventilated patient who has been sedated and immobile for 10 days is being considered for early mobilisation. The primary rationale is to:', '["Increase the risk of complications", "Reduce ICU-acquired weakness, shorten ventilator days, and speed functional recovery", "Have no measurable effect on outcomes", "Replace the need for any physiotherapy input"]'::jsonb, 1, 'Early mobilisation, when safe, reduces ICU-acquired weakness, can shorten mechanical ventilation duration, and improves longer-term functional recovery.', 'Rehabilitation & Mobilization', '🏃', true),
(3496, 'Physiotherapy (CCN 425)', 'AI Practice Question', 'Contraindications to chest physiotherapy include all of the following EXCEPT:', '["Untreated pneumothorax", "Active haemoptysis", "Uncontrolled raised intracranial pressure", "Mild, stable chronic bronchitis"]'::jsonb, 3, 'Stable chronic bronchitis is actually an indication rather than a contraindication for chest physiotherapy; untreated pneumothorax, active haemoptysis and uncontrolled raised ICP are recognised contraindications/precautions.', 'Rehabilitation & Mobilization', '🏃', true),
(3497, 'Anaesthesia Scenarios (CCN 415)', 'AI Practice Question', 'A patient is extubated after general anaesthesia and shortly develops high-pitched inspiratory stridor. The nurse should suspect:', '["Normal post-extubation voice change with no concern", "Laryngospasm or airway oedema, requiring urgent assessment and possible intervention", "Improved airway patency", "A sign of adequate recovery"]'::jsonb, 1, 'Stridor after extubation suggests laryngospasm or airway oedema/obstruction, both requiring urgent assessment and prompt intervention to prevent complete airway obstruction.', 'Anaesthesia & Perioperative Care', '💉', true),
(3498, 'Anaesthesia Scenarios (CCN 415)', 'AI Practice Question', 'A patient in the recovery room after general anaesthesia has delayed emergence (remains unrousable well beyond expected time). The nurse should consider all of the following causes EXCEPT:', '["Residual anaesthetic/opioid/sedative effect", "Hypoglycaemia or metabolic derangement", "Improved cerebral perfusion", "Intraoperative stroke or other neurological event"]'::jsonb, 2, 'Improved cerebral perfusion would not cause delayed emergence — residual drug effect, metabolic derangement, and neurological events are all recognised causes requiring evaluation.', 'Anaesthesia & Perioperative Care', '💉', true),
(3499, 'Anaesthesia Scenarios (CCN 415)', 'AI Practice Question', 'A patient in the PACU has a pulse oximetry reading of 90% on room air, with shallow respirations and drowsiness after opioid analgesia. The nurse''s priority action is to:', '["Document and reassess in one hour", "Stimulate the patient, apply supplemental oxygen, and consider naloxone per protocol while notifying the anaesthetist", "Increase the opioid dose to help the patient rest", "Discharge the patient to the ward immediately"]'::jsonb, 1, 'Hypoxaemia with drowsiness and shallow breathing after opioids suggests opioid-induced respiratory depression, requiring prompt stimulation, oxygen, possible naloxone, and physician notification.', 'Anaesthesia & Perioperative Care', '💉', true),
(3500, 'Radiology Scenarios (CCN 427)', 'AI Practice Question', 'A ventilated patient''s chest X-ray shows the endotracheal tube tip sitting in the right main bronchus. The nurse should anticipate:', '["No action is needed, since this is the correct position", "The tube needs to be withdrawn slightly, since this position risks left lung collapse and right lung barotrauma", "The patient should be extubated immediately", "Increasing the tidal volume to compensate"]'::jsonb, 1, 'An ETT that has migrated into the right main bronchus effectively excludes the left lung from ventilation (risking collapse) and over-ventilates the right lung (risking barotrauma) — the tube must be withdrawn to the correct position.', 'Radiology & Imaging', '🩻', true),
(3501, 'Radiology Scenarios (CCN 427)', 'AI Practice Question', 'A patient develops sudden chest pain and dyspnoea after central line insertion. A chest X-ray shows a hyperlucent area with absent lung markings on the same side. This confirms:', '["Normal post-procedure findings", "Pneumothorax, a recognised complication of central line insertion", "Pleural effusion", "Successful catheter placement with no complication"]'::jsonb, 1, 'A hyperlucent area with absent lung markings after central line insertion confirms pneumothorax, a well-recognised procedural complication requiring prompt management.', 'Radiology & Imaging', '🩻', true),
(3502, 'Laboratory Sciences Scenarios (CCN 426)', 'AI Practice Question', 'A patient''s arterial blood gas is drawn but there is an air bubble in the syringe before it is capped. The nurse should recognise this could:', '["Have no effect on the results", "Falsely alter PaO2 and PaCO2 results, since room air can diffuse into the sample", "Only affect the pH reading", "Improve the accuracy of the sample"]'::jsonb, 1, 'Air bubbles in an ABG sample can cause gas exchange with room air, falsely altering PaO2 and PaCO2 results — bubbles should be expelled promptly and the sample analysed quickly.', 'Laboratory Sciences & Haematology', '🔬', true),
(3503, 'Laboratory Sciences Scenarios (CCN 426)', 'AI Practice Question', 'A patient''s laboratory results show low haemoglobin, low platelets, and schistocytes on peripheral smear, alongside active bleeding from IV sites. This combination should raise suspicion for:', '["Simple iron deficiency anaemia", "Disseminated Intravascular Coagulation (DIC)", "Normal findings with no significance", "Vitamin B12 deficiency"]'::jsonb, 1, 'Schistocytes (fragmented red cells) with thrombocytopenia and active bleeding are classic laboratory findings supporting a diagnosis of DIC.', 'Laboratory Sciences & Haematology', '🔬', true),
(3504, 'ICT Scenarios', 'AI Practice Question', 'A hospital''s electronic health record system experiences a temporary outage. The nurse''s most appropriate immediate action is to:', '["Stop all patient care until the system returns", "Follow the unit''s downtime/contingency procedure (e.g. paper documentation) to ensure continuity of safe care", "Guess at patient information from memory with no documentation", "Discharge all patients immediately"]'::jsonb, 1, 'Hospitals maintain downtime/contingency procedures (often paper-based) for EHR outages, ensuring safe continuity of care and documentation until the system is restored.', 'Nursing Informatics & ICT', '💻', true),
(3505, 'Anatomy & Physiology Scenarios (CCN 410)', 'AI Practice Question', 'A patient with chronic kidney disease develops anaemia. The nurse understands this is partly explained by the kidney''s normal physiological role in:', '["Producing red blood cells directly", "Producing erythropoietin, which stimulates red blood cell production in the bone marrow", "Storing iron for red blood cell production", "Filtering red blood cells from urine"]'::jsonb, 1, 'The kidneys produce erythropoietin, which stimulates red blood cell production in the bone marrow — CKD reduces erythropoietin production, contributing to anaemia.', 'Anatomy & Physiology', '🧬', true),
(3506, 'Anatomy & Physiology Scenarios (CCN 410)', 'AI Practice Question', 'A patient''s arterial blood gas shows low PaO2 despite adequate ventilation. The nurse considers that this could reflect a problem with:', '["The heart''s electrical conduction system only", "Gaseous exchange at the alveolar-capillary membrane", "The urinary bladder", "The endocrine pancreas"]'::jsonb, 1, 'Impaired oxygenation despite adequate ventilation often reflects a gas exchange problem at the alveolar-capillary membrane (e.g. from fluid, inflammation or V/Q mismatch), rather than a ventilation problem itself.', 'Anatomy & Physiology', '🧬', true),
(3507, 'Disaster Nursing Scenarios', 'AI Practice Question', 'During a multi-vehicle road traffic accident with 15 casualties and limited ambulances, the triage officer applies START triage. A casualty who is breathing at 35/min after airway repositioning is categorised as:', '["Minor (green) — can wait", "Immediate (red) — respiratory rate outside the normal range signals urgent priority", "Deceased (black)", "Delayed (yellow)"]'::jsonb, 1, 'In START triage, a respiratory rate above 30/min (or below 10, or apnoeic even after repositioning) places the casualty in the immediate (red) category for urgent treatment.', 'Disaster & Emergency Nursing', '🚨', true),
(3508, 'Disaster Nursing Scenarios', 'AI Practice Question', 'A nurse arriving at a mass casualty scene notices a downed power line near several casualties. The correct first action is to:', '["Rush immediately to help the nearest casualty regardless of the power line", "Ensure the scene is safe (e.g. await utility company/appropriate personnel to secure the hazard) before approaching", "Move the power line personally to clear a path", "Ignore the hazard since helping casualties is the priority"]'::jsonb, 1, 'Scene safety always comes first — approaching a live electrical hazard without it being properly secured risks the responder becoming an additional casualty, which helps no one.', 'Disaster & Emergency Nursing', '🚨', true),
(3509, 'Mixed Revision Scenarios', 'AI Practice Question', 'A patient is admitted to the ICU following a suicide attempt by drug overdose. Once medically stabilised, the nurse''s priority alongside physical care is to:', '["Avoid discussing the event with the patient entirely", "Assess psychiatric risk, ensure a safe environment, and involve mental health/psychiatric services", "Discharge the patient as soon as vital signs normalise, with no further assessment", "Focus exclusively on physical recovery with no psychological assessment"]'::jsonb, 1, 'Care after a suicide attempt must include psychiatric risk assessment, ensuring a safe environment (e.g. removing means of harm), and timely involvement of mental health services, alongside physical stabilisation.', 'Mixed Revision', '📚', true),
(3510, 'Mixed Revision Scenarios', 'AI Practice Question', 'A nurse is caring for a critically ill patient whose family speaks a different language and no interpreter is immediately available. The most appropriate action is to:', '["Proceed with care and consent discussions using only gestures and assumptions", "Access a professional interpreter service (in-person or telephone/video) rather than relying on family members for medical interpretation, especially for consent", "Use a family member, including a child, to interpret regardless of the sensitivity of the information", "Delay all care until family happens to bring a bilingual friend"]'::jsonb, 1, 'Professional interpreter services should be used for medical communication and consent, since relying on family members (especially children) risks inaccurate interpretation and inappropriate burden on the family member.', 'Mixed Revision', '📚', true),
(3511, 'Mixed Revision Scenarios', 'AI Practice Question', 'A nurse notices that a colleague appears to be under the influence of alcohol while on duty in the ICU. The most appropriate immediate action is to:', '["Say nothing and continue working alongside them as normal", "Remove the colleague from direct patient care duties and report the concern through appropriate management/reporting channels immediately", "Cover for the colleague to protect their job", "Wait until the end of the shift to raise any concern"]'::jsonb, 1, 'Patient safety takes priority — a colleague suspected of being impaired must be removed from direct care immediately and the concern reported promptly through proper channels.', 'Mixed Revision', '📚', true),
(3512, 'Mixed Revision Scenarios', 'AI Practice Question', 'A patient''s family requests that the patient not be told their terminal diagnosis, though the patient (who has full decision-making capacity) has asked directly about their prognosis. The nurse''s most appropriate approach is to:', '["Automatically follow the family''s wishes over the patient''s own request", "Respect the competent patient''s autonomy and right to information, while sensitively working with the family to understand their concerns", "Refuse to discuss the situation with either party", "Tell the patient nothing and avoid the topic indefinitely"]'::jsonb, 1, 'A competent patient''s right to information about their own condition generally takes priority over family preference to withhold it, while the care team works sensitively to understand and address family concerns.', 'Mixed Revision', '📚', true),
(3513, 'Mixed Revision Scenarios', 'AI Practice Question', 'A patient''s oxygen saturation probe consistently reads falsely low despite the patient appearing clinically well. The nurse should first consider:', '["Immediately intubating the patient", "Technical causes such as poor peripheral perfusion, nail polish, motion artefact, or probe malposition before assuming true hypoxaemia", "Assuming the reading is always accurate with no further check", "Ignoring the reading entirely with no clinical correlation"]'::jsonb, 1, 'Pulse oximetry can be affected by technical factors like poor perfusion, nail polish, or motion — these should be considered and corrected before assuming the reading reflects true hypoxaemia, though clinical correlation is always needed.', 'Mixed Revision', '📚', true),
(3514, 'Mixed Revision Scenarios', 'AI Practice Question', 'A patient''s care plan includes a goal that was fully achieved before the planned evaluation date. The nurse''s most appropriate action is to:', '["Leave the care plan unchanged until the original date", "Document the goal as met and revise the care plan to reflect new or ongoing needs", "Ignore the achievement and continue the same interventions unnecessarily", "Discharge the patient immediately regardless of other needs"]'::jsonb, 1, 'Care plans should be dynamically updated — when a goal is achieved early, this should be documented and the plan revised to address remaining or new needs, not left static.', 'Mixed Revision', '📚', true),
(3515, 'ICU Prioritisation Scenarios', 'AI Practice Question', 'A nurse is assigned four ICU patients at the start of a shift. Which patient should be assessed FIRST?', '["A patient who is stable and due for a routine dressing change", "A patient with a new drop in oxygen saturation from 96% to 84%", "A patient waiting for a scheduled physiotherapy session", "A patient asking for their meal tray"]'::jsonb, 1, 'A significant, acute drop in oxygen saturation represents an actual or potential airway/breathing emergency and must be assessed immediately over stable, routine, or non-urgent requests.', 'Mixed Revision', '📚', true),
(3516, 'ICU Prioritisation Scenarios', 'AI Practice Question', 'Using the ABCDE framework to prioritise care for a newly admitted critically ill patient, which finding would take priority over the others?', '["Mild abrasions on the forearm", "Stridor with visible respiratory distress", "A blood pressure of 128/82", "A pain score of 3/10"]'::jsonb, 1, 'Stridor with respiratory distress represents an airway problem — the highest priority in the ABCDE framework — overriding lower-priority findings like minor wounds or mild pain.', 'Mixed Revision', '📚', true),
(3517, 'ICU Prioritisation Scenarios', 'AI Practice Question', 'A nurse receiving handover for a new patient is told the patient has a DNR (Do Not Resuscitate) order. If the patient develops a reversible airway obstruction (e.g. from a food bolus, unrelated to their terminal condition), the nurse should:', '["Do nothing since DNR means withholding all care", "Still intervene appropriately for a reversible emergency, since DNR specifically refers to withholding cardiopulmonary resuscitation, not all treatment", "Wait for family permission before any action", "Immediately begin chest compressions regardless of the obstruction"]'::jsonb, 1, 'A DNR order specifically addresses CPR in the event of cardiac/respiratory arrest — it does not mean withholding all other appropriate care, such as clearing a reversible airway obstruction.', 'Ethics, Law & Management', '⚖️', true),
(3518, 'Communication Scenarios', 'AI Practice Question', 'During a critical patient handover between shifts, using the SBAR (Situation-Background-Assessment-Recommendation) framework primarily helps to:', '["Make handover longer and more complicated", "Structure communication clearly and concisely, reducing the risk of missed or miscommunicated critical information", "Replace the need for any written documentation", "Only apply to nurse-to-nurse communication, never nurse-to-physician"]'::jsonb, 1, 'SBAR provides a clear, structured communication framework shown to reduce miscommunication and missed information during handovers, applicable across all interprofessional communication.', 'Mixed Revision', '📚', true),
(3519, 'Post-Op Complications Scenarios', 'AI Practice Question', 'A patient two days post-abdominal surgery develops sudden, sharp chest pain, tachypnoea, and tachycardia. The nurse''s priority concern is:', '["Simple incisional pain radiating to the chest", "Pulmonary embolism, given the post-operative VTE risk", "Normal post-anaesthetic recovery", "Mild anxiety with no clinical significance"]'::jsonb, 1, 'Post-operative patients are at elevated VTE risk — sudden chest pain with tachypnoea/tachycardia should raise urgent suspicion for pulmonary embolism requiring prompt evaluation.', 'Mixed Revision', '📚', true),
(3520, 'Post-Op Complications Scenarios', 'AI Practice Question', 'A patient''s surgical wound shows increasing redness, warmth, and purulent discharge on post-operative day 4, with a fever of 38.6°C. The nurse should suspect:', '["Normal wound healing", "Surgical site infection, requiring assessment, wound culture, and physician notification", "A drug reaction", "No clinical significance"]'::jsonb, 1, 'Increasing redness, warmth, purulent discharge and fever are classic signs of surgical site infection requiring prompt assessment and reporting.', 'Mixed Revision', '📚', true),
(3521, 'Post-Op Complications Scenarios', 'AI Practice Question', 'A patient develops abdominal wound dehiscence with visible bowel loops (evisceration) after a coughing fit. The immediate nursing action is to:', '["Push the bowel back into the abdomen manually", "Cover the exposed bowel with sterile saline-soaked gauze, keep the patient calm and NPO, and call for immediate surgical help", "Apply a dry dressing and continue the shift as normal", "Encourage the patient to walk immediately"]'::jsonb, 1, 'Evisceration is a surgical emergency — cover exposed bowel with sterile saline-soaked gauze (never push it back in), keep the patient calm/NPO, and summon immediate surgical assistance.', 'Mixed Revision', '📚', true),
(3522, 'Post-Op Complications Scenarios', 'AI Practice Question', 'A patient recovering from surgery develops confusion, agitation, and disorientation on post-operative day 2, with no prior history of cognitive impairment. This is most consistent with:', '["Baseline dementia", "Postoperative delirium", "Normal anaesthesia recovery expected for weeks", "A permanent neurological condition"]'::jsonb, 1, 'New-onset confusion/agitation in the days following surgery, especially in older patients, is characteristic of postoperative delirium, which is often multifactorial and potentially reversible.', 'Mixed Revision', '📚', true),
(3523, 'Cardiovascular Scenarios', 'AI Practice Question', 'A patient with heart failure receiving digoxin has a potassium level of 3.0mmol/L. The nurse should recognise this combination as significant because it:', '["Has no bearing on digoxin''s effect", "Increases the risk of digoxin toxicity and arrhythmia", "Reduces the risk of digoxin toxicity", "Only affects blood pressure, not cardiac rhythm"]'::jsonb, 1, 'Hypokalaemia increases myocardial sensitivity to digoxin, raising the risk of toxicity and arrhythmia even at otherwise therapeutic digoxin levels.', 'Cardiovascular', '🫀', true),
(3524, 'Respiratory Scenarios', 'AI Practice Question', 'A patient with COPD exacerbation is prescribed controlled oxygen therapy via a Venturi mask at a precise FiO2. The rationale for using a Venturi mask over a simple face mask in this patient is to:', '["Deliver a precisely controlled, consistent oxygen concentration to avoid over-oxygenation risk", "Deliver the highest possible oxygen concentration regardless of precision", "Avoid any oxygen delivery at all", "Provide humidification only, with no oxygen"]'::jsonb, 0, 'A Venturi mask delivers a precise, fixed FiO2, which is important in COPD patients at risk of CO2 retention from excessive, uncontrolled oxygen therapy.', 'Respiratory', '🫁', true),
(3525, 'Neurology Scenarios', 'AI Practice Question', 'A patient is assessed as GCS E3 V4 M5. The total GCS score is:', '["10", "12", "15", "8"]'::jsonb, 1, 'Summing the components: Eye opening 3 + Verbal response 4 + Motor response 5 = 12.', 'Neurology', '🧠', true),
(3526, 'Renal Scenarios', 'AI Practice Question', 'A patient''s urine output is measured at 20ml over the last hour, with a weight of 70kg. This represents a urine output of approximately:', '["0.3ml/kg/hr, consistent with oliguria requiring assessment", "2ml/kg/hr, a normal finding", "5ml/kg/hr, indicating polyuria", "No clinical significance regardless of the value"]'::jsonb, 0, '20ml/hr ÷ 70kg ≈ 0.29ml/kg/hr, below the generally accepted minimum of 0.5ml/kg/hr, indicating oliguria requiring prompt assessment.', 'Renal & Fluid Balance', '💧', true),
(3527, 'Burns Scenarios', 'AI Practice Question', 'A patient with 25% TBSA burns is being assessed for signs of burn shock (SIRS response) in the first 48 hours. The nurse should anticipate:', '["No systemic effects with burns below 30%", "Systemic inflammatory response and significant fluid shifts, since burns over roughly 20% TBSA can trigger burn shock", "Improved haemodynamic stability compared to baseline", "No need for fluid resuscitation"]'::jsonb, 1, 'Burns exceeding approximately 20% TBSA can trigger a systemic inflammatory response (burn shock) with significant fluid shifts, requiring aggressive, carefully calculated fluid resuscitation.', 'Burns & Trauma', '🔥', true),
(3528, 'Obstetric Scenarios', 'AI Practice Question', 'A woman in active labour develops a sudden onset of severe abdominal pain, vaginal bleeding, and a change in fetal heart rate pattern to bradycardia after a previous caesarean section. This should raise suspicion for:', '["Normal labour progress", "Uterine rupture at the site of the previous caesarean scar", "Simple round ligament pain", "Braxton Hicks contractions"]'::jsonb, 1, 'Sudden severe pain, bleeding and fetal distress in a labouring patient with a prior caesarean section raises urgent concern for uterine rupture, an obstetric emergency.', 'Obstetric & Neonatal', '🤱', true),
(3529, 'GI/Endocrine Scenarios', 'AI Practice Question', 'A patient with acute severe ulcerative colitis develops abdominal distension, fever, and tachycardia, with a colon diameter over 6cm on imaging. This presentation raises concern for:', '["Normal disease flare with no urgency", "Toxic megacolon, a life-threatening complication requiring urgent surgical consultation", "Simple constipation", "Irritable bowel syndrome"]'::jsonb, 1, 'Colonic dilation with systemic toxicity (fever, tachycardia) in severe colitis suggests toxic megacolon, a life-threatening complication carrying a high risk of perforation.', 'GI, Endocrine & Metabolic', '🍽️', true),
(3530, 'Infection Prevention Scenarios', 'AI Practice Question', 'A patient with Clostridioides difficile infection requires which type of isolation precaution?', '["Airborne precautions with N95 respirator", "Contact precautions, with gown and gloves, and hand hygiene using soap and water (not alcohol-based sanitiser alone) given spore resistance", "No precautions are necessary", "Droplet precautions only"]'::jsonb, 1, 'C. difficile requires contact precautions, and hand hygiene must use soap and water (mechanical removal), since alcohol-based sanitisers do not reliably kill C. difficile spores.', 'Infection Prevention', '🦠', true),
(3531, 'Pharmacology Scenarios', 'AI Practice Question', 'A patient receiving IV fentanyl for analgesia develops chest wall rigidity making ventilation difficult. This uncommon but serious complication is best managed with:', '["Increasing the fentanyl dose further", "Stopping the infusion, providing ventilatory support, and administering a neuromuscular blocker/naloxone as directed if severe", "Ignoring the finding since it is expected", "Administering an antihistamine"]'::jsonb, 1, 'Fentanyl-induced chest wall rigidity (''wooden chest syndrome'') impairs ventilation and requires stopping the drug, supporting ventilation, and reversal or neuromuscular blockade as directed in severe cases.', 'ICU Pharmacology', '💊', true),
(3532, 'Ethico-Legal Scenarios', 'AI Practice Question', 'A nurse is asked by a patient''s employer for information about the patient''s diagnosis and prognosis. The nurse''s appropriate response is to:', '["Provide the requested information immediately, since the employer is asking on the patient''s behalf", "Decline to share any information without the patient''s explicit, documented consent, citing confidentiality obligations", "Share only positive information", "Share information only if the employer insists strongly"]'::jsonb, 1, 'Patient confidentiality obligations mean health information cannot be disclosed to third parties, including employers, without the patient''s explicit informed consent.', 'Ethics, Law & Management', '⚖️', true),
(3533, 'Research Scenarios', 'AI Practice Question', 'A nurse researcher wants to study the lived experience of ICU patients after discharge. The most appropriate research approach for this question is:', '["A strictly quantitative, numerical survey with no narrative data", "A qualitative approach (e.g. interviews) to capture rich, descriptive experiential data", "No research method is appropriate for this topic", "A laboratory experiment"]'::jsonb, 1, 'Exploring lived experience and subjective meaning is best suited to qualitative research methods (e.g. interviews, thematic analysis), which capture rich descriptive data rather than purely numerical measures.', 'Research & Nursing Process', '📊', true),
(3534, 'Management Scenarios', 'AI Practice Question', 'A nurse manager is reviewing an incident where a critical lab value was not communicated to the physician for several hours. The most effective response focuses on:', '["Identifying and blaming the individual nurse involved only, with no system review", "Reviewing the communication process/system for gaps and implementing changes to prevent recurrence, alongside individual feedback where appropriate", "Ignoring the incident since the patient was not harmed", "Removing all critical value alert systems"]'::jsonb, 1, 'Effective incident review focuses on identifying and fixing systemic gaps (not just blaming an individual), while still providing appropriate individual feedback where relevant — a ''just culture'' approach.', 'Ethics, Law & Management', '⚖️', true),
(3535, 'Anatomy & Physiology Scenarios', 'AI Practice Question', 'A patient with severe liver disease develops ascites and peripheral oedema. The nurse understands this is partly explained by the liver''s reduced synthesis of:', '["Red blood cells", "Albumin, reducing plasma oncotic pressure and allowing fluid to shift into tissues/peritoneal cavity", "Insulin only", "White blood cells"]'::jsonb, 1, 'The liver normally synthesises albumin, which maintains plasma oncotic pressure — reduced albumin in liver disease allows fluid to shift out of the vasculature, contributing to ascites and oedema.', 'Anatomy & Physiology', '🧬', true),
(3536, 'Disaster Nursing Scenarios', 'AI Practice Question', 'In the aftermath of a building collapse, a rescued casualty has been trapped under heavy debris for over 4 hours with a crushed limb. Before full extraction, the team should anticipate and prepare for:', '["No special precautions beyond normal trauma care", "Crush syndrome, with hyperkalaemia and myoglobin release upon reperfusion, requiring pre-extraction fluid resuscitation where possible", "Immediate limb amputation regardless of viability", "No need for cardiac monitoring"]'::jsonb, 1, 'Prolonged limb entrapment risks crush syndrome — on reperfusion, released potassium and myoglobin can cause fatal arrhythmia and acute kidney injury, so fluid resuscitation before/during extraction is a key preventive measure.', 'Disaster & Emergency Nursing', '🚨', true),
(3537, 'Lab Sciences Scenarios', 'AI Practice Question', 'A patient''s coagulation panel shows a markedly prolonged PT/INR with normal aPTT. This pattern most specifically suggests an abnormality in:', '["The intrinsic coagulation pathway only", "The extrinsic coagulation pathway (e.g. Factor VII deficiency or warfarin effect)", "Platelet function only", "No coagulation abnormality"]'::jsonb, 1, 'An isolated prolonged PT/INR with normal aPTT points toward the extrinsic pathway (Factor VII), classically seen with warfarin therapy or early vitamin K deficiency.', 'Laboratory Sciences & Haematology', '🔬', true)
