-- CCN Council Prep Pro — practice question batch 5
-- 236 AI-generated labeled practice questions — a large mixed batch combining
-- scenario/vignette-style clinical judgement questions with straight recall questions,
-- spanning every major curriculum domain (Cardiovascular, Respiratory, Neurology, Renal,
-- Shock/Sepsis, Burns/Trauma, GI/Endocrine, Obstetric/Neonatal, Infection Prevention,
-- Pharmacology, Ethics/Management, Research/Nursing Process, plus Anaesthesia, Radiology,
-- Lab Sciences, ICT, Physiotherapy, Disaster Nursing and Anatomy & Physiology).
-- source='AI Practice Question' on every row.
-- Run this once in the Supabase SQL Editor (Project -> SQL Editor -> New query).

on conflict (id) do update set topic=excluded.topic, source=excluded.source, q=excluded.q, opts=excluded.opts, ans_idx=excluded.ans_idx, exp=excluded.exp, category=excluded.category, category_icon=excluded.category_icon, is_active=true;